window.NZ_OPISY=window.NZ_OPISY||{};window.NZ_OPISY["f"]={"Franciszek": "<b>Franciszek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie wywodzące się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a> określenia <i>francesco</i> oznaczającego \"Francuza, Francuzika\", jakim kupiec Piotr Bernardone (ojciec <a href=\"https://pl.wikipedia.org/wiki/Franciszek_z_Asy%C5%BCu\" target=\"_blank\" rel=\"noopener noreferrer\">św. Franciszka z Asyżu</a>) nazwał swego syna Jana, gdy ten wrócił z Francji. W Asyżu zaczęto powszechnie nazywać chłopca tym określeniem i pod takim imieniem znany jest powszechnie.", "Filip": "Nosił je np. <a href=\"https://pl.wikipedia.org/wiki/Filip_II_Macedo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Filip II Macedoński</a>, ojciec <a href=\"https://pl.wikipedia.org/wiki/Aleksander_Macedo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksandra Wielkiego</a>. Żeńskie odpowiedniki tego imienia to <a href=\"https://pl.wikipedia.org/wiki/Filipina\" target=\"_blank\" rel=\"noopener noreferrer\">Filipina</a>, <a href=\"https://pl.wikipedia.org/wiki/Filipa\" target=\"_blank\" rel=\"noopener noreferrer\">Filipa</a>. Nazwiska pochodzące od Filipa: <a href=\"https://pl.wikipedia.org/wiki/Filipowicz\" target=\"_blank\" rel=\"noopener noreferrer\">Filipowicz</a>, Filipczak, Filipek, Filipowski, Filipkowski. Nazwa państwa <a href=\"https://pl.wikipedia.org/wiki/Filipiny\" target=\"_blank\" rel=\"noopener noreferrer\">Filipiny</a> pochodzi od imienia króla Hiszpanii <a href=\"https://pl.wikipedia.org/wiki/Filip_II_Habsburg\" target=\"_blank\" rel=\"noopener noreferrer\">Filipa II Habsburga</a>.", "Fabian": "<b>Fabian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „należący do Fabiusza” (mężczyzny z rodu Fabiuszów). Nazwa rodowa Fabiuszy wywodzi się zaś od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>faba</em> (<a href=\"https://pl.wikipedia.org/wiki/B%C3%B3b\" target=\"_blank\" rel=\"noopener noreferrer\">bób</a>) i pierwotnie oznaczała osobę zajmującą się uprawą bobu. Chrześcijańskim patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Fabian_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Fabian, papież</a>.", "Feliks": "<b>Feliks</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>felix</em> – łaskawy, szczęśliwy) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Żeńskie odpowiedniki: <a href=\"https://pl.wikipedia.org/wiki/Feliksa\" target=\"_blank\" rel=\"noopener noreferrer\">Feliksa</a>, <a href=\"https://pl.wikipedia.org/wiki/Felicja\" target=\"_blank\" rel=\"noopener noreferrer\">Felicja</a>.", "Florian": "<b>Florian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego „kwitnący kwiat”. W Polsce używane bywało w formie <b>Tworzyjan</b>. Od Floriana wywodzi się także czeski neologizm <i>Květoslav</i>.", "Fryderyk": "<b>Fryderyk</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niem.</a> <i>Friedrich</i>). Dawniej adaptowane do języka polskiego w formach <i>Biedrzych</i>, <i>Berdych</i>.", "Ferdynand": "<b>Ferdynand</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów oznaczających „pokój” i „odważny, śmiały” (por. <a href=\"https://pl.wikipedia.org/wiki/Winand\" target=\"_blank\" rel=\"noopener noreferrer\">Winand</a>).", "Fedir": "<p>Fedir (ukraina: Федір FEHD-ihr) to męskie ukraińskie imię oznaczające \"dar Boga\" lub \"od Boga\" pochodzące od starożytnej greckiej nazwy Theodoros. Powszechne warianty nazwy w języku angielskim obejmują Teddy i Ted, które są diminutiwami Theodore.</p>", "Frank": "<p>Frank - debiutancki album studiowy brytyjskiej piosenkarki Amy Winehouse, wydany 20 października 2003 roku przez Island Records. Album zajął trzynaste miejsce w brytyjskich listach.</p>", "Fernando": "<p>Fernando: Fernando - hiszpańskie imię i nazwisko Fernando - skrócenie botaniczne, które oznacza, że autorem taksy jest Edwin Fernando.  ⁇ Fernando ⁇ - singel ze zespołu ABBA.</p>", "Felix": "<p>Felix (lat. Felix - ⁇ płodny, owocny, szczęśliwy, dobrobytny, błogosławiony, bogaty) - imię męskie.</p>", "Francisco": "<p>Francisco (hisp. Francisco) - hiszpańskie imię i nazwisko męskie, w innych językach występują warianty - Francisco, Francesco, Francisc.</p>", "Felicjan": "<b>Felicjan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, powstałe jako przydomek od imienia <a href=\"https://pl.wikipedia.org/wiki/Feliks\" target=\"_blank\" rel=\"noopener noreferrer\">Feliks</a> i bliźniacze do niego znaczeniowo. <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%9Bci%C3%B3%C5%82_katolicki\" target=\"_blank\" rel=\"noopener noreferrer\">Kościół katolicki</a> notuje licznych świętych o tym imieniu.", "Federico": "<p>Fredericko (włoski)  Federico, ok.</p>", "Franek": "<p>Franek (czeski: Franek) - własna nazwa; rozpowszechniona w postaci nazwisk.</p>", "Franz": "<p>Franz (niemiecki Franz, od frank - ⁇ wolny, odważny ⁇) - niemieckie imię męskie.</p>", "Florin": "<p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Fiodor": "W Polsce nadawane co najmniej od XIII wieku i zapisywane m.in. w postaci: <i>Tader</i>, <i>Chodor</i> (wschsł.), <i>Teodor</i>, <i>Todor</i>, <i>C(z)ader</i>, <i>C(z)eder</i>. Odpowiednikiem znaczeniowym tego imienia wśród imion staropolskich jest <a href=\"https://pl.wikipedia.org/wiki/Dadzbog\" target=\"_blank\" rel=\"noopener noreferrer\">Dadzbog</a>, <a href=\"https://pl.wikipedia.org/wiki/Bo%C5%BCydar_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Bożydar</a>, <a href=\"https://pl.wikipedia.org/wiki/Bogdan\" target=\"_blank\" rel=\"noopener noreferrer\">Bogdan</a>, <a href=\"https://pl.wikipedia.org/wiki/Bogdan\" target=\"_blank\" rel=\"noopener noreferrer\">Bohdan</a>.", "François": "<p>François (francuski) - francuskie imię i nazwisko mężczyzn (włoski - Francuasa).</p>", "Franco": "<p>Juan Manuel Antonio do Amaral Franco (port. João Manuel Antonio do Amaral Franco; 25 czerwca 1921 - 8 maja 2009) - portugalski botanik, profesor botaniki, ⁇ patryarch portugalskich botaniki ⁇ .</p>", "Friedrich": "<p>Hans Christian Friedrich (niem. Hans Christian Friedrich, 1925 - 1992) - niemiecki botanik.</p>", "Fati̇h": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fatiha</b>.</p><b>Fatiha</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> <b>ﻓﺘﻴﺤﺔ</b>) – arabskie imię żeńskie. Pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Tytu%C5%82_(literaturoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">tytułu</a> pierwszej sury <a href=\"https://pl.wikipedia.org/wiki/Koran\" target=\"_blank\" rel=\"noopener noreferrer\">Koranu</a> <a href=\"https://pl.wikipedia.org/wiki/Al-Fatiha\" target=\"_blank\" rel=\"noopener noreferrer\">Al-Fatihy</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> الفاتحة).", "Fatih": "<p>Fatih jest dzielnicą w prowincji Istanbul w Turcji. Ogromnie obszarzyła 13 km2 i liczba ludności w 2007 roku wynosiła 422941 osób, a jego gęstość 32534 osób/km2.</p>", "Frederik": "<p>Frederik (d. 11 października 1753 - 7 grudnia 1805) - królewski książę Danii i Norwegii, syn króla Fredericka V i jego drugiej żony Juliany Marie Braunschweig-Wolfenbütetelski.</p>", "Faustyn": "<b>Faustyn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od rzymskiego nazwiska <i>Faustinus</i>, które pierwotnie oznaczało „pochodzący od <a href=\"https://pl.wikipedia.org/wiki/Faust_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Fausta</a>, należący do Fausta”. Imię to nosiło wielu świętych, a jednym ze znanych jest św. Faustyn, wspominany 15 lutego ze swoim bratem, św. <a href=\"https://pl.wikipedia.org/wiki/Jowita\" target=\"_blank\" rel=\"noopener noreferrer\">Jowitą</a>. Łacińska grupa, od której imię to pochodzi (<i>faustus</i> — „błogi, pomyślny”, ale także <i>faveo, favi, fautum</i> — „sprzyjać, być przychylnym”) nie ma pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_indoeuropejskie\" target=\"_blank\" rel=\"noopener noreferrer\">indoeuropejskiego</a> oraz pewnych odpowiedników w żadnym języku indoeuropejskim.", "Francois": "<p>François (francuski: [fʁɑ̃swa]) to francuskie męskie imię i nazwisko, równoważne angielskiej nazwie Francis.</p>", "Frédéric": "<p>Frederik (dat. Frederik, angielski.</p>", "Fedor": "<p>Fyodor, Fedor (rosyjski: Фёдор) lub Feodor jest rosyjską formą greckiego imienia Theodoros (grecki: Θεόδωρος) oznaczającego \"Boży dar\" lub \"od Boga\". Fedora (Федора) jest kobiecą formą.</p>", "Fredy": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fredi</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fred</b>.</p><p>August Frederick ⁇ Fred\" Kammer Jr.; 3 czerwca 1912, Brooklyn - 21 lutego 1996, Hob-Sound) - amerykański hokejista i golfa, brązowy zwycięzca zimowych igrzysk olimpijskich 1936.</p>", "Fuad": "<p>Fuad (arabski: َفؤَاد fū\"ād, fou\"ād) (zwany również Fouad, Foud, Fuaad lub Foad) jest męskim arabskim nazwiskiem, co oznacza \"serce\" - bijące się serce, pojęcie \"umysłu i ducha\". Jego pierwotnym słowem jest arabski czasownik fa'ada (arabski: َفَأَد), co oznacza \"palenie lub płomień\", a lahmun fa'eed, co oznacza \"masło pieczone na ognie\".</p>", "Ferdinand": "<p>⁇ Ferdinand ⁇ (niem. Ferdinand) - niemiecka ciężka samodzielna-artyleryjna instalacja okresu II wojny światowej klasy myśliwców czołgów.</p>", "Franklin": "<p>James Franklin (około 1783 - 31 sierpnia 1834) - brytyjski żołnierz i naturalista.</p>", "Fritz": "<p>Fritz (od niemieckiego Fritz, Friz): Fritz - niemieckie nazwisko.</p>", "Ferenc": "<b>Franciszek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie wywodzące się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a> określenia <i>francesco</i> oznaczającego \"Francuza, Francuzika\", jakim kupiec Piotr Bernardone (ojciec <a href=\"https://pl.wikipedia.org/wiki/Franciszek_z_Asy%C5%BCu\" target=\"_blank\" rel=\"noopener noreferrer\">św. Franciszka z Asyżu</a>) nazwał swego syna Jana, gdy ten wrócił z Francji. W Asyżu zaczęto powszechnie nazywać chłopca tym określeniem i pod takim imieniem znany jest powszechnie.", "Fredrik": "<p>Fredrik - szwedzka indy-grupa z Malmów, Szwecja. Jej uczestnikami byli Fredrik Haltin, Ola Lindelfelt i Anna Moberg.</p>", "Franck": "<p>Franck d.d. - horowadzka firma produkująca kawę, herbatę i różne śniaky (poczęki).</p>", "Farhad": "<p>Farhad (perskiego: فرهاد, romanized: Farhād), również pisane Ferhad, Ferhod, Farhod lub Ferhat, jest powszechną perską nazwą męską używaną od Partów, po raz pierwszy zarejestrowaną dla królów Arsacid około 170 pne. Warianty nazwy są również powszechnie stosowane w innych krajach o historycznych wpływach perskiego, takich jak Afganistan, Bangladesz, Irak, Tadżykistan, Uzbekistan i region autonomiczny Chin w Xinjiang.</p>", "Fred": "<p>August Frederick ⁇ Fred\" Kammer Jr.; 3 czerwca 1912, Brooklyn - 21 lutego 1996, Hob-Sound) - amerykański hokejista i golfa, brązowy zwycięzca zimowych igrzysk olimpijskich 1936.</p>", "Félix": "<p>Félix Urgel (w 818, Lion) - biskup Urzeła (781 - 792 i 798 - 799), jeden z głównych obrońców adopsji.</p>", "Flawiusz": "<b>Flawiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <a href=\"https://pl.wikipedia.org/wiki/Flawiusze\" target=\"_blank\" rel=\"noopener noreferrer\">Flawiuszów</a>. Po łacinie znaczy \"złoty\".", "Fares": "<b>Peres</b> lub <b>Fares</b> − postać biblijna z <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Rodzaju\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Rodzaju</a>, syn <a href=\"https://pl.wikipedia.org/wiki/Juda_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Judy</a> i jego synowej <a href=\"https://pl.wikipedia.org/wiki/Tamar_(synowa_Judy)\" target=\"_blank\" rel=\"noopener noreferrer\">Tamar</a>. Jego bratem bliźniakiem był Zerach, a braćmi przyrodnimi <a href=\"https://pl.wikipedia.org/wiki/Er_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Er</a>, <a href=\"https://pl.wikipedia.org/wiki/Onan\" target=\"_blank\" rel=\"noopener noreferrer\">Onan</a> i <a href=\"https://pl.wikipedia.org/wiki/Szela\" target=\"_blank\" rel=\"noopener noreferrer\">Szela</a>. Od Peresa pochodzi ród Parsytów.", "Frankie": "<p>Frankie lub Franky mogą odnosić się do:</p>", "Frants": "<p>Frants to imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą: Frants Banner (zmarł 1575), duński właściciel ziemi i lensmann Frants Berg (1504-1591), duński duchowny, biskup Oslo Frants Beyer (1851-1918), norweski średniwy regulator, inspektor podatkowy i kompozytor Frants Diderik Bøe, (1820-1891), norweska malarz, Anna Frants (ur. 1965), amerykański artysta multimedialny, kurator i kolekcjoner sztuki Karl-August Frants (1895-1942), estyjski...</p>", "Fariz": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fariza</b>.</p><p>Fariza jest miastem w prowincji Zamora, Kastilia i Leon, Hiszpania. Według przeprowadzonego w 2004 roku popytu (INE) mieście miało 689 mieszkańców.</p>", "Fahad": "<p>Fahd (arabski: فهد, \"leopard\" lub \"cheetah\"), również przetransliterowany Fahed lub Fahad, może odnosić się do:</p>", "Fryc": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fryderyk</b>.</p><b>Fryderyk</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niem.</a> <i>Friedrich</i>). Dawniej adaptowane do języka polskiego w formach <i>Biedrzych</i>, <i>Berdych</i>.", "Florent": "<b>Florencjusz</b>, <b>Florenty</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, występujące w Polsce już w <a href=\"https://pl.wikipedia.org/wiki/XII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XII wieku</a> (<a href=\"https://pl.wikipedia.org/wiki/1175\" target=\"_blank\" rel=\"noopener noreferrer\">1175</a> r.). Powstało ono od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomka</a> <i>Florentius</i>, utworzonego poprzez dodanie <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostka</a> <i>-ius</i> od innego przydomka, <i>Florens</i> (łac. <i>florens</i>, <i>-ntis</i> — \"kwitnący\"). Istnieją liczni święci patroni tego imienia (nawet dwudziestu), m.in. św. <a href=\"https://pl.wikipedia.org/wiki/Florencjusz_z_Populonii\" target=\"_blank\" rel=\"noopener noreferrer\">Florencjusz z Populonii</a>, biskup (<a href=\"https://pl.wikipedia.org/wiki/IV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">IV wiek</a>).", "Fortunat": "<b>Fortunat</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>.", "Finley": "<p>Finley (wygłaszane ⁇ Finle ⁇) - włoski zespół rockowy utworzony w 2002 roku. Grupa została nazwana w cześć Michaela Finley'ego, amerykańskiego profesjonalnego koszykarza NBA.</p>", "Frans": "<p>Francis Osifo Jeppsson Wall (szwedz. Frans Osifoh Jeppsson Wall; rodzaj.</p>", "Fathi": "<p>Fathi (arabsko: فَتْحِي fat·ḥiy/ fat·ḥī/ fat··ḥy) to arabskie imię i nazwisko w formie posiadanej, co oznacza \"wygrywający, triumfujący\". Może odnosić się do:</p>", "Feodor": "<p>Fyodor, Fedor (rosyjski: Фёдор) lub Feodor jest rosyjską formą greckiego imienia Theodoros (grecki: Θεόδωρος) oznaczającego \"Boży dar\" lub \"od Boga\". Fedora (Федора) jest kobiecą formą.</p>", "Freddie": "<p>Fereti Vaval \"Freddie\" Tuilagi (ur. 9 czerwca 1971 w Apia) - samoński rugbyściak i gracz w rugby, występujący w pozycji winga i centrum.</p>", "Francisco Javier": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Francisco</b>.</p><p>Francisco (hisp. Francisco) - hiszpańskie imię i nazwisko męskie, w innych językach występują warianty - Francisco, Francesco, Francisc.</p>", "Farai": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fara</b>.</p>W <a href=\"https://pl.wikipedia.org/wiki/Etnolekt_%C5%9Bl%C4%85ski\" target=\"_blank\" rel=\"noopener noreferrer\">etnolekcie śląskim</a> fara oznacza budynek probostwa (podobnie jak w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">języku czeskim</a>), a farorzem mianuje się proboszcza danej parafii (czeski: farář).", "Fernandez": "<p>Fernández (Hiszpańska) - hiszpańska nazwisko.</p>", "Fidelis": "<b>Fidelis</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>fidelis</em> – „wierny, pewny”. Oznacza zatem człowieka „pełnego wiary”. Współczesną jego formą w języku hiszpańskim jest Fidel.", "Flores": "<p>Flóres (hisz. Flores - ⁇ kwiecie ⁇) - hiszpańska nazwisko i toponim.</p>", "Fan": "Nazwa wywodzi się od zapisu skróconej formy słowa <a href=\"https://pl.wikipedia.org/wiki/Fanatyzm\" target=\"_blank\" rel=\"noopener noreferrer\">fanatyk</a>. Nie posiada jednak pejoratywnego znaczenia, a nawet ma pozytywny wydźwięk.", "Farman": "<p>Henri Farman (francuski: Henri Farman)  Henri Farman, angielski.</p>", "Farkhad": "<p>Farhad (perskiego: فرهاد, romanized: Farhād), również pisane Ferhad, Ferhod, Farhod lub Ferhat, jest powszechną perską nazwą męską używaną od Partów, po raz pierwszy zarejestrowaną dla królów Arsacid około 170 pne. Warianty nazwy są również powszechnie stosowane w innych krajach o historycznych wpływach perskiego, takich jak Afganistan, Bangladesz, Irak, Tadżykistan, Uzbekistan i region autonomiczny Chin w Xinjiang.</p>", "Fethi": "<p>Fethi jest tureckim pisownią arabskiej nazwy Fathi (arabski: فَتْحِي fat·ḥiy/ fat·ḥī/ fat··ḥy) co oznacza \"wygrywający, triumfujący\". Do wybitnych osób z tym nazwiskiem należą:</p>", "Franc": "<p>Franc jest ogólną nazwą kilku jednostek monetarnych, zwłaszcza franku francuskiego - francuskiej jednostki monetarnej. Francusz francuski był na rynku do czasu, gdy w 1999 r. przyjęto ustawodawstwo w sprawie użycia euro i wprowadziło go w życie w 2002 r.</p>", "Florentin": "<p>Florentin lub Florentín (od łacińskiego Florentinus) może być nazwiskiem lub nazwiskiem. Znajduje się jako imię u rumuńskich, niemieckich, francuskich i hiszpańskich.</p>", "Faiz": "<p>Kamen Rider 555 (仮面ライダー555 (ファイズ), Kamen Raidā Faizu, Kamen Rader Faiz, Masked Rider Φ's, Phi's, lub Faiz) to japoński serial telewizyjny Tokusatsu. Jest to 13. część serii Kamen Rider, wspólnego współpracy między Toei i Ishimori Productions.</p>", "Fraser": "<p>Louis Fraser (ang. Louis Fraser; 1810 - 1866) - brytyjski zoolog, kolekcjoner i kurator, konsul.</p>", "Fahim": "<p>Faheem, również pisane Fahiem, Fahim lub Fehim (arabski: فَهِيم, romanized: Fahīm, lit. 'rozróżniający') jest męskim imieniem cypryjskiego pochodzenia arabskiego, używanym również jako nazwisko, oznaczające 'czucie', 'rozumienie', 'keen' lub 'inteligentny', pochodzący z korzeni słowa f-h-m, znajdującego się w Koranie 21:79.</p>", "Fayez": "<p>Fayez (arabsko: فَائِز) to arabskie imię dla mężczyzn, wariant Faiz. Mieszkańcy nazwanych Fayez to: Fayez Bandar (ur. 1983), Kuwaicki piłkarz Fayez Ghosn (1950-2021), libański polityk Fayez Sarofim (1929-2022), koptycki egipski amerykański menedżer funduszy Fayez al-Tarawneh (1949-2021), były premier Jordanii</p>", "Ferit": "<p>Ferryt lub ferryt może być: W metalistyce jest to wrzemiosło żelaza z strukturą krysztaliczną złożoną z obszaru. Zobacz Ferrit.</p>", "Flawian": "<b>Flawian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwy <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <a href=\"https://pl.wikipedia.org/wiki/Flawiusze\" target=\"_blank\" rel=\"noopener noreferrer\">Flawiuszów</a>. Oznacza <i>flavus</i> - \"żółty, płowy, złoty\". Wśród patronów - m.in. św. Flawian II, <a href=\"https://pl.wikipedia.org/wiki/Patriarcha_Antiochii\" target=\"_blank\" rel=\"noopener noreferrer\">biskup Antiochii</a>.", "Fady": "<p>Fady, Al Fady lub Fadey to arabskie imię męskie oznaczające \"odkupca, zbawiciel\". Fady może odnosić się do:</p>", "Filemon": "<b>Filemon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>philé</i> – „miłuję, kocham” lub od <i>phil-mosýn</i> – „przyjazność, życzliwość”, czyli „życzliwy, przyjazny”. Żyjący <a href=\"https://pl.wikipedia.org/wiki/Nowy_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">w czasach biblijnych</a> <a href=\"https://pl.wikipedia.org/wiki/Filemon_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Św. Filemon</a> był <a href=\"https://pl.wikipedia.org/wiki/List_do_Filemona\" target=\"_blank\" rel=\"noopener noreferrer\">jednym z adresatów listów</a> <a href=\"https://pl.wikipedia.org/wiki/Pawe%C5%82_z_Tarsu\" target=\"_blank\" rel=\"noopener noreferrer\">św. Pawła</a>.", "Femi": "<p>Fẹ́mi to powszechne Nigerijskie imię pochodzenia joruba, które oznacza \"kochaj mnie\". Femi jest najczęściej diminutiwnym określeniem \"Olufemi\" (lub Olúfẹ́mi), co oznacza, że Pan mnie kocha.</p>", "Fatmir": "<p>Fatmir to albaniańska męska nazwa, związek z albaniańskiego tłuszczu (e) (luck) z łacińskiego \"fati\" i mirë (dobry) również z łaciński \"mirus/mirum\". Do wybitnych osób z nazwiskiem należą: Fatmir Agalliu (1933-1998), albanianki akademik Fatmir Besimi (ur. 1975), makedonian polityk i ekonomista etnicznej etniki Fatmir Bushi (ur. 1963), albanianki ciężarosta Fatmir Caca (ur. 1985), albanian football defender Fatmir Dalladaku ...</p>", "Fergus": "<p>Fergus (lat. Fergus, Fergustian; zmarł ok.</p>", "Falk": "<p>Johann (Юхан) Peter Falck (szwedzki Johan Peter Falck, 20 stycznia 1732 - 12 kwietnia (31 marca) 1774) - rosyjski i szwedzki podróżnik i naturalista (przede wszystkim botanik), badacz natury Rosji.</p>", "Frydolin": "<b>Frydolin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Nosił to imię <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aw._Frydolin\" target=\"_blank\" rel=\"noopener noreferrer\">św. Frydolin</a>.", "Fathy": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fathi</b>.</p><p>Fathi (arabsko: فَتْحِي fat·ḥiy/ fat·ḥī/ fat··ḥy) to arabskie imię i nazwisko w formie posiadanej, co oznacza \"wygrywający, triumfujący\". Może odnosić się do:</p>", "Fortune": "<p>Fortune: Fortune to skrócie botaniczne, oznaczające, że autorem taksy jest Robert Fortune. Fortune to amerykański czasopismo.</p>", "Faouzi": "<p>Fawzi, Faouzi, Fawzy lub Fevzi (w arabski: فوزي) to arabskie imię i nazwisko oznaczające \"triumf\". Do wybitnych osób z tym nazwiskiem należą:</p>", "Fadil": "<p>Fazl (arabski: فضل) to arabskie słowo oznaczające łaskę lub cnótę. Może być również przetłumaczana jako Fadl lub z dodaniem dodatkowej vokalu.</p>", "Feliciano": "<p>Feliciano (szp. Feliciano, port.</p>", "Festus": "<b>Festus</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego \"święto\" lub \"festiwal\". Pojawia się w <a href=\"https://pl.wikipedia.org/wiki/Nowy_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Nowym Testamencie</a> jako przydomek rzymskiego urzędnika. Jest to imię dwóch świętych katolickich.", "Fillip": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Filip</b>.</p>Nosił je np. <a href=\"https://pl.wikipedia.org/wiki/Filip_II_Macedo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Filip II Macedoński</a>, ojciec <a href=\"https://pl.wikipedia.org/wiki/Aleksander_Macedo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksandra Wielkiego</a>. Żeńskie odpowiedniki tego imienia to <a href=\"https://pl.wikipedia.org/wiki/Filipina\" target=\"_blank\" rel=\"noopener noreferrer\">Filipina</a>, <a href=\"https://pl.wikipedia.org/wiki/Filipa\" target=\"_blank\" rel=\"noopener noreferrer\">Filipa</a>. Nazwiska pochodzące od Filipa: <a href=\"https://pl.wikipedia.org/wiki/Filipowicz\" target=\"_blank\" rel=\"noopener noreferrer\">Filipowicz</a>, Filipczak, Filipek, Filipowski, Filipkowski. Nazwa państwa <a href=\"https://pl.wikipedia.org/wiki/Filipiny\" target=\"_blank\" rel=\"noopener noreferrer\">Filipiny</a> pochodzi od imienia króla Hiszpanii <a href=\"https://pl.wikipedia.org/wiki/Filip_II_Habsburg\" target=\"_blank\" rel=\"noopener noreferrer\">Filipa II Habsburga</a>.", "Faust": "<b>Faust</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>faustus</em>, „błogi, szczęśliwy”), należące do niedużej grupy najstarszych <a href=\"https://pl.wikipedia.org/wiki/Imiona_%C5%82aci%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion rzymskich</a> (imion właściwych, <i>praenomen</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Marek\" target=\"_blank\" rel=\"noopener noreferrer\">Marek</a>, <a href=\"https://pl.wikipedia.org/wiki/Tyberiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyberiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Tytus\" target=\"_blank\" rel=\"noopener noreferrer\">Tytus</a>), i oznaczające „szczęśliwie rosnący”. Łacińska grupa, od której imię to pochodzi (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>faustus</em> – \"błogi, pomyślny\", ale także <i>faveo, favi, fautum</i> – \"sprzyjać, być przychylnym\") nie ma pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_indoeuropejskie\" target=\"_blank\" rel=\"noopener noreferrer\">indoeuropejskiego</a> oraz pewnych odpowiedników w żadnym języku indoeuropejskim.", "Faycal": "<p>Faisal, Faisel, Fayçal lub Faysal (arabski: فيصل) to arabskie imię. Faisal, Fayçal lub Faysal mogą również odnosić się do:</p>", "Finlay": "<p>Finlay to męskie imię i nazwisko. Nazwa jest przedstawiana w szkockim gagelickim jako Fionnlagh.</p>", "Fozil": "<p>Fozil jest męskim imieniem pochodzenia arabskiego, wariantem Fazila. Do wybitnych osób z tym nazwiskiem należą: Fozil Amirov (1914-1979), sowiecki uzbekski naukowiec Fozil Musaev (ur. 1989), uzbekska piłkarz</p>", "Flemming": "<b>Flemming (<i>Flemingowie</i>, <i>Flemmingowie</i>, <i>von Flemming</i>)</b> – <a href=\"https://pl.wikipedia.org/wiki/Niemcy\" target=\"_blank\" rel=\"noopener noreferrer\">zniemczony</a> <a href=\"https://pl.wikipedia.org/wiki/Flamandowie\" target=\"_blank\" rel=\"noopener noreferrer\">flamandzki</a> <a href=\"https://pl.wikipedia.org/wiki/R%C3%B3d\" target=\"_blank\" rel=\"noopener noreferrer\">ród</a> <a href=\"https://pl.wikipedia.org/wiki/Szlachta\" target=\"_blank\" rel=\"noopener noreferrer\">szlachecki</a>, wywodzący się z <a href=\"https://pl.wikipedia.org/wiki/Flandria_(region)\" target=\"_blank\" rel=\"noopener noreferrer\">Flandrii</a> (dzisiejsza <a href=\"https://pl.wikipedia.org/wiki/Belgia\" target=\"_blank\" rel=\"noopener noreferrer\">Belgia</a>), zamieszkujący <a href=\"https://pl.wikipedia.org/wiki/Pomorze_Zachodnie\" target=\"_blank\" rel=\"noopener noreferrer\">Pomorze Zachodnie</a> od okresu <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecza</a> (XIII w.) do XIX/XX wieku.", "Falko": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Falk</b>.</p><p>Johann (Юхан) Peter Falck (szwedzki Johan Peter Falck, 20 stycznia 1732 - 12 kwietnia (31 marca) 1774) - rosyjski i szwedzki podróżnik i naturalista (przede wszystkim botanik), badacz natury Rosji.</p>", "Frantisek": "<p>František to męskie czeskie i słowackie imię. Jest krewnym Franciszka, Franciszka, François i Franz.</p>", "Frederyk": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Frederik</b>.</p><p>Frederik (d. 11 października 1753 - 7 grudnia 1805) - królewski książę Danii i Norwegii, syn króla Fredericka V i jego drugiej żony Juliany Marie Braunschweig-Wolfenbütetelski.</p>", "Faheem": "<p>Faheem, również pisane Fahiem, Fahim lub Fehim (arabski: فَهِيم, romanized: Fahīm, lit. 'rozróżniający') jest męskim imieniem cypryjskiego pochodzenia arabskiego, używanym również jako nazwisko, oznaczające 'czucie', 'rozumienie', 'keen' lub 'inteligentny', pochodzący z korzeni słowa f-h-m, znajdującego się w Koranie 21:79.</p>", "Faton": "<p>Faton to imię. Znanymi osobami z nazwiska są: Faton Bislimi (ur. 1983), albaniański aktywista Faton Macula, albanianki gitarzysta Faton Maloku (ur. 1991), kosowskiego piłkarza Faton Peci (ur. 1982), albanieckiego polityka Faton Popova (ur. 1984), niemiecko-albanieckie piłkarz Faton Toski (ur. 1987), niemiecki piłkarze Faton Xhemaili (ur. 1998), albanianki piłkerz</p>", "Flamur": "<p>Flamur to albaniańska męska nazwa, wywodzi się z albaniańskiego słowa flamur, co oznacza \"flag\". Wśród znanych osób nosijących nazwę Flamur są: Flamur Bajrami (ur. 1997), kosowski piłkarz Flamur Dzelili (ur. 1999), szwedzki piłkarze Flamur Kastrati (ur. 1991), kosowsky piłkarzem Flamur Noka (ur. 1971), albański polityk, były minister spraw wewnętrznych Flamur Ruçi (ur. 2002), albański piłkarzek Flamur Tairi (ur. 1990),...</p>", "Flavius": "<p>Flavius (lat. Flavius; zmarł 30 sierpnia 536) - biskup Reima (535 - 536).</p>", "Fakhraddin": "<p>Fakhr al-Din (arabski: فخر الدين) to arabskie imię męskie i (w współczesnym użyciu) nazwisko, co oznacza honor / dumę religii. Alternatywne transliteracje obejmują Fachreddin, Fakhreddine, Fahrettin, Fakraddin, Fakhhreddin, Fahruddin, Fexredîn itp.</p>", "Fylyp": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Filip</b>.</p>Nosił je np. <a href=\"https://pl.wikipedia.org/wiki/Filip_II_Macedo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Filip II Macedoński</a>, ojciec <a href=\"https://pl.wikipedia.org/wiki/Aleksander_Macedo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksandra Wielkiego</a>. Żeńskie odpowiedniki tego imienia to <a href=\"https://pl.wikipedia.org/wiki/Filipina\" target=\"_blank\" rel=\"noopener noreferrer\">Filipina</a>, <a href=\"https://pl.wikipedia.org/wiki/Filipa\" target=\"_blank\" rel=\"noopener noreferrer\">Filipa</a>. Nazwiska pochodzące od Filipa: <a href=\"https://pl.wikipedia.org/wiki/Filipowicz\" target=\"_blank\" rel=\"noopener noreferrer\">Filipowicz</a>, Filipczak, Filipek, Filipowski, Filipkowski. Nazwa państwa <a href=\"https://pl.wikipedia.org/wiki/Filipiny\" target=\"_blank\" rel=\"noopener noreferrer\">Filipiny</a> pochodzi od imienia króla Hiszpanii <a href=\"https://pl.wikipedia.org/wiki/Filip_II_Habsburg\" target=\"_blank\" rel=\"noopener noreferrer\">Filipa II Habsburga</a>.", "Flynn": "<p>Flynn jest irlandzką nazwą lub nazwiskiem, angliczowaną formą irlandzkiego Ó Floinn lub prawdopodobnie Mac Floinn, co oznacza \"płodzenie lub syn Flann\" (bienawo oznacza \"czerwony (skomplekcja) \" lub \"rudy\"). Nazwa jest częściej używana jako nazwisko niż imię pierwsze.</p>", "Franky": "<p>Frankie lub Franky mogą odnosić się do:</p>", "Fabian Andres": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Fabian</b>.</p><b>Fabian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „należący do Fabiusza” (mężczyzny z rodu Fabiuszów). Nazwa rodowa Fabiuszy wywodzi się zaś od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>faba</em> (<a href=\"https://pl.wikipedia.org/wiki/B%C3%B3b\" target=\"_blank\" rel=\"noopener noreferrer\">bób</a>) i pierwotnie oznaczała osobę zajmującą się uprawą bobu. Chrześcijańskim patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Fabian_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Fabian, papież</a>.", "Filon": "<b>Filon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, gr. <i>Φιλων (Filon)</i>, które pochodzi od <i>φιλεω (fileo)</i> – \"kochać\" i oznacza \"kochający\". Patronem tego imienia jest św. Filon, wspominany razem ze św. Agatopodem.", "Faizali": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Faizal</b>.</p><p>Faizal to męskie imię. Jest również używane jako nazwisko.</p>", "Fayzulla": "<p>Faizullah, również pisany jako Fayzullah lub Feizollah (arabsko: فيض الله) to męskie muzułmańskie imię, składające się z elementów Faiz i Allah. To znaczy sukces od Boga lub zwycięstwo od Boga.</p>", "Fatjon": "<p>Fatjon to męskie imię pochodzenia albańskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Forest": "<p>Forest (ang. Forest, z angielskiego.</p>", "Fyodor": "<p>Fyodor, Fedor (rosyjski: Фёдор) lub Feodor jest rosyjską formą greckiego imienia Theodoros (grecki: Θεόδωρος) oznaczającego \"Boży dar\" lub \"od Boga\". Fedora (Федора) jest kobiecą formą.</p>", "Ferran": "<p>Ferran (francuski: Ferran) - comuna we Francji, znajdująca się w regionie Langeдок - Russilon.</p>", "Fawad": "<p>Fawad to nazwisko arabskiego pochodzenia. Do wybitnych osób z nazwiskiem należą: Fawad Ahmed (ur. 1982), pakistańsko-australijski kryker Fawad Alam (ur. 1985), pakistański kryker Fawad Ali (ur. 1986), pakistajski kryker Falhad Chaudhry, pakistański polityk Fawad Hasan Fawad (ur. 1960), pakistańskiego polityka Fawad Jalal, pakistańskiej aktorki Fawad Khan (ur. 1981), pakistańczyka Fawad Khan, kryker (ur. 1986), pakistański Kryker Fawada Rana...</p>", "Faber": "<p>Faber (niemiecki: Faber) - nazwisko.</p>", "Faizal": "<p>Faizal to męskie imię. Jest również używane jako nazwisko.</p>", "Faraz": "<p>Faraz to męskie imię i nazwisko pochodzące z perskich języków i oznacza \"wywyższenie\". Jest odziedziczony z średnio perskiego [Księga Pahlavi potrzebna] (prʾc), ⁇ .</p>", "Fadel": "<p>Fadel (z arabskiej: فضل or Fadil, arabskiejஃ فاضل) to arabskie imię męskie, co oznacza \"oddzielne, szanowne, wyższe\". Do wybitnych osób z tym nazwiskiem należą:</p>", "Florea": "<p>Florea jest zarówno rumuńskim nazwiskiem, jak i męskim rumuńskie nazwisko. Znani ludzie z nazwiska obejmują: Nazwa: Daniel Florea, rumunski piłkarz Daniel Florea , rumuński polityk Daniel Constantin Florea , rumunski futbolista Dick Florea , amerykański telewizyjny John Florea , fotograf Laurențiu Florea , Rumunski piłki nożnej Nikolay Florea (1912-1941), ukraiński radziecki astronom Răzvan Florea , Rumuński pływacz Sandu ...</p>", "Fox": "<p>Fox, FOX (z angielskiego - ⁇ lisas ⁇): Volkswagen Fox - samochód miejski produkowany przez Volkswagen-Brazylii dla lokalnego rynku Fox - zbudowy bezpilotowy aparat lotniczy FOX toolkit - trans-platformna biblioteka narzędzi z otwartym kodem wyjściowym do budowy interfejsu graficznego użytkownika.</p>", "Fethullah": "<p>Fathallah, Fathalla lub tureckie wariant Fethullah jest transliteracją arabskiej nazwy, فتح الله (Fatḥ Allāh), zbudowane z arabskich słów fath i Allah. Jest to jedno z wielu arabskich nazw teoforycznych, które oznaczają \"otwarcie (otwarcie) Allaha\" lub \"podbojowanie Boga\".</p>", "François-Xavier": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>François</b>.</p><p>François (francuski) - francuskie imię i nazwisko mężczyzn (włoski - Francuasa).</p>", "Franz-Josef": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Franz</b>.</p><p>Franz (niemiecki Franz, od frank - ⁇ wolny, odważny ⁇) - niemieckie imię męskie.</p>", "Florentino": "<p>Florentino to zarówno męskie imię, jak i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Florentyn": "<b>Florentyn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, genetycznie wtórne cognomen <i>Florentinus</i>, utworzone od pierwotnego <i>Florentius</i> Istnieją liczni święci patroni tego imienia, m.in. św. Florentyn (+357), męczennik burgundzki wspominany <a href=\"https://pl.wikipedia.org/wiki/27_wrze%C5%9Bnia\" target=\"_blank\" rel=\"noopener noreferrer\">27 września</a>.", "Fawaz": "<p>Fawaz (czasami Fawwaz lub Fawez) jest męskim arabskim nazwiskiem i nazwiskiem. Dosłowne znaczenie tego słowa jest \"wygrywający\", ponieważ jest to przymiotnik męski z czasownika faz fāz, co oznacza \"wygrał\".</p>", "Francisco Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Francisco</b>.</p><p>Francisco (hisp. Francisco) - hiszpańskie imię i nazwisko męskie, w innych językach występują warianty - Francisco, Francesco, Francisc.</p>", "Ferid": "<p>Farid (arabski: فَرِيد fariyd, farīd), również śpiewany Fareed lub Ferid i akcentujący się Férid, jest arabskim męskim imieniem osobistym lub nazwiskiem, które oznacza \"jedyną, jedyną w swoim rodzaju (\"Jeden\"), nieporównywalną\". W wielu społecznościach, w tym na Bliskim Wschodzie, na Bałkanach, w Afryce Północnej i Azji Południowo-Wschodniej, nazwa Farid jest powszechna przez wiele pokoleń.</p>", "Forrest": "<p>George Forrest (ang. George Forrest; 13 marca 1873 - 5 stycznia 1932) - szkocki botanik, podróżnik po Chinach.</p>", "Fionn": "\"Fionn” (lub „Finn”) to w rzeczywistości pseudonim oznaczający „jasny” – w odniesieniu do koloru włosów, a w niektórych wersjach – również „biały”, co dotyczy czystości.", "Fabiusz": "<b>Fabiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się nazwy rzymskiego rodu Fabiuszów, która z kolei pochodzi od łacińskiego <i>faba</i> - \"bób\". Wśród patronów tego imienia — św. Fabiusz, wspominany razem ze swoimi towarzyszami, św. Bassusem, <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Maksym\" target=\"_blank\" rel=\"noopener noreferrer\">Maksymem</a> i <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Antym\" target=\"_blank\" rel=\"noopener noreferrer\">Antymem</a>.", "Fahd": "<p>Fahd (arabski: فهد, \"leopard\" lub \"cheetah\"), również przetransliterowany Fahed lub Fahad, może odnosić się do:</p>", "Fidan": "<p>Fidan to nazwisko kobiety pochodzące z Turcji, które oznacza \"sąpienie\". Słowo to ma jednak greckie korzenie.</p>", "Fazli": "<p>Fazli (persk: فضلی) może odnosić się do:</p>", "Fahed": "<p>Fahd (arabski: فهد, \"leopard\" lub \"cheetah\"), również przetransliterowany Fahed lub Fahad, może odnosić się do:</p>", "Firmin": "<b>Firmin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „należący do <a href=\"https://pl.wikipedia.org/wiki/Firmus_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Firmusa</a>” lub stanowiące spieszczenie imienia <a href=\"https://pl.wikipedia.org/wiki/Firmus_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Firmus</a>, które z kolei pochodzi od słowa <i>firmus</i>, 'mocny, pewny, stały, trwały'. Wśród patronów - <a href=\"https://pl.wikipedia.org/wiki/Firmin_(biskup_Amiens)\" target=\"_blank\" rel=\"noopener noreferrer\">św. Firmin (biskup Amiens)</a>.", "Fuentes": "<p>Fuentes jest miastem w prowincji Cuenca, hiszpańskiej samorządu Castile-La Mancha. Miasto to ma powierzchnię 107,6 km2, liczba ludności w 2009 roku wynosi 508 osób z gęstością ludźmi/km2.</p>", "Fawzy": "<p>Fawzi, Faouzi, Fawzy lub Fevzi (w arabski: فوزي) to arabskie imię i nazwisko oznaczające \"triumf\". Do wybitnych osób z tym nazwiskiem należą:</p>", "Francisco Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Francisco</b>.</p><p>Francisco (hisp. Francisco) - hiszpańskie imię i nazwisko męskie, w innych językach występują warianty - Francisco, Francesco, Francisc.</p>", "Foued": "<p>Fuad (arabski: َفؤَاد fū\"ād, fou\"ād) (zwany również Fouad, Foud, Fuaad lub Foad) jest męskim arabskim nazwiskiem, co oznacza \"serce\" - bijące się serce, pojęcie \"umysłu i ducha\". Jego pierwotnym słowem jest arabski czasownik fa'ada (arabski: َفَأَد), co oznacza \"palenie lub płomień\", a lahmun fa'eed, co oznacza \"masło pieczone na ognie\".</p>", "Firman": "<b>Firman</b> – w dawnych państwach <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmańskich</a> określenie oficjalnych dokumentów wystawianych przez władcę (<a href=\"https://pl.wikipedia.org/wiki/Su%C5%82tan\" target=\"_blank\" rel=\"noopener noreferrer\">sułtana</a>). Firman zawierał osobisty pisemny rozkaz i był pieczętowany sułtańską pieczęcią. Słowo pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">perskiego</a> słowa <i>farmân</i> (فرمان), znaczącego <i>dekret</i> lub <i>nakaz</i>. W sułtańskiej Turcji używana była forma <i>ferman</i>.", "Fahmi": "<p>Fahmi (arabski: فهمي) jest arabską nazwą w formie posiadanej słowa fahm (arabsko: فَهْم) oznaczającej \"rozumienie, zrozumienie, wiedzę\" i pochodzącą z czasownika fahima (arabsku: فَہِمَ) oznaczającego \"przyjaciele wiedzą o\", \"uświadomienie, zrozumiałość lub zrozumienie\". Może odnosić się do:</p>", "Fatah": "<p>Ruch za wyzwolenie narodowe Palestyny (arabski: حَرَكَةُ ٱلتَّحْرِيرِ ٱلْوَتَنِيِّ ٱلْفِلَسْطِينِيِّ , Ḥaracat al-Taḥrir al-Vaṭanӣ ль-Filast́нӣ), bardziej znany jako FATH (arabsko: FATH).</p>", "Francisc": "<p>Franciszek jest rumuńską formą Franciszka. Franciszek jest w innych przypadkach rumuńską formą węgierskiego imienia Ferenc.</p>", "Frode": "<b>Frode</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">Język staronordyjski</a>: <i>Frōði</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staroangielski\" target=\"_blank\" rel=\"noopener noreferrer\">język staroangielski</a>: <i>Frōda</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_%C5%9Brednio-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">język średnio-wysoko-niemiecki</a>: <i>Vruote</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_norweski\" target=\"_blank\" rel=\"noopener noreferrer\">język norweski</a> i <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_du%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">duński</a>: <i>Frode</i>) – norweskie, oraz duńskie imię męskie oznaczające „mądry”, „uczony” lub „sprytny”. Miało je nosić wielu legendarnych królów <a href=\"https://pl.wikipedia.org/wiki/Legendarni_w%C5%82adcy_Danii\" target=\"_blank\" rel=\"noopener noreferrer\">Danii</a> według dzieł takich jak: <i><a href=\"https://pl.wikipedia.org/wiki/Beowulf\" target=\"_blank\" rel=\"noopener noreferrer\">Beowulf</a></i>, <i><a href=\"https://pl.wikipedia.org/wiki/Edda_m%C5%82odsza\" target=\"_blank\" rel=\"noopener noreferrer\">Edda młodsza</a></i>, <i><a href=\"https://pl.wikipedia.org/wiki/Gesta_Danorum\" target=\"_blank\" rel=\"noopener noreferrer\">Gesta Danorum</a></i>, <i><a href=\"https://pl.wikipedia.org/wiki/Heimskringla\" target=\"_blank\" rel=\"noopener noreferrer\">Saga o Ynglingach</a></i>, czy <i>Grottasöngr</i>. <i>Gesta Danorum</i> wymienia aż sześciu władców o tym imieniu. Forma „Frōði” jest w dalszym ciągu używana w języku <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_islandzki\" target=\"_blank\" rel=\"noopener noreferrer\">islandzkim</a>, czy <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_farerski\" target=\"_blank\" rel=\"noopener noreferrer\">farerskim</a>. Zlatynizowaną formą imienia jest „Frotho”, bądź „Frodo”. Została ona użyta przez <a href=\"https://pl.wikipedia.org/wiki/J.R.R._Tolkien\" target=\"_blank\" rel=\"noopener noreferrer\">Johna Ronalda Reuela Tolkiena</a> w trylogii <a href=\"https://pl.wikipedia.org/wiki/W%C5%82adca_pier%C5%9Bcieni\" target=\"_blank\" rel=\"noopener noreferrer\">Władca pierścieni</a>. Jeden z bohaterów dzieła nosi imię <a href=\"https://pl.wikipedia.org/wiki/Frodo_Baggins\" target=\"_blank\" rel=\"noopener noreferrer\">Frodo</a>. W <a href=\"https://pl.wikipedia.org/wiki/2008\" target=\"_blank\" rel=\"noopener noreferrer\">2008</a> roku imię Frode nosiło w <a href=\"https://pl.wikipedia.org/wiki/Norwegia\" target=\"_blank\" rel=\"noopener noreferrer\">Norwegii</a> 11384 osób, w <a href=\"https://pl.wikipedia.org/wiki/Dania\" target=\"_blank\" rel=\"noopener noreferrer\">Danii</a> około 1413, a w <a href=\"https://pl.wikipedia.org/wiki/Szwecja\" target=\"_blank\" rel=\"noopener noreferrer\">Szwecji</a> około 307 mężczyzn.", "Froilan": "<p>Froilan lub Froilán to męskie imię. Do wybitnych osób z nazwiskiem należą: Froilán de León, katolicki święty Felipe de Marichalar y Borbón, znany jako Froilán, hiszpański szlachetny Froilan Baguion, filipiński piłkarz koszykówki Froilan Calayag, filipińskiego malarza Froilán Díaz, argentyńskiego piłkarza Froilan Quiño, filipińskiego polityka Froilan Saludar, filipiinskiego bokserza Froilana Tantaleana, peruwskiego strzelca sportowego Froilan Tenorio (1939-2020), północnego...</p>", "Fareed": "<p>Farid (arabski: فَرِيد fariyd, farīd), również śpiewany Fareed lub Ferid i akcentujący się Férid, jest arabskim męskim imieniem osobistym lub nazwiskiem, które oznacza \"jedyną, jedyną w swoim rodzaju (\"Jeden\"), nieporównywalną\". W wielu społecznościach, w tym na Bliskim Wschodzie, na Bałkanach, w Afryce Północnej i Azji Południowo-Wschodniej, nazwa Farid jest powszechna przez wiele pokoleń.</p>", "Fintan": "<b>Fintan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Celtowie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>, polski odpowiednik celtyckiego imienia <i>Fionntán</i>, które prawdopodobnie oznaczało \"biały ogień\" lub \"biały byk\". Jest to imię wielu irlandzkich świętych.", "Florencjusz": "<b>Florencjusz</b>, <b>Florenty</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, występujące w Polsce już w <a href=\"https://pl.wikipedia.org/wiki/XII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XII wieku</a> (<a href=\"https://pl.wikipedia.org/wiki/1175\" target=\"_blank\" rel=\"noopener noreferrer\">1175</a> r.). Powstało ono od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomka</a> <i>Florentius</i>, utworzonego poprzez dodanie <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostka</a> <i>-ius</i> od innego przydomka, <i>Florens</i> (łac. <i>florens</i>, <i>-ntis</i> — \"kwitnący\"). Istnieją liczni święci patroni tego imienia (nawet dwudziestu), m.in. św. <a href=\"https://pl.wikipedia.org/wiki/Florencjusz_z_Populonii\" target=\"_blank\" rel=\"noopener noreferrer\">Florencjusz z Populonii</a>, biskup (<a href=\"https://pl.wikipedia.org/wiki/IV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">IV wiek</a>).", "Farshad": "<p>Farshad to męskie imię i nazwisko pochodzące z Persu. Do wybitnych osób z tym nazwiskiem należą:</p>", "Florin-Alexandru": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Fatos": "<p>Fatos to albanska miana męska, co oznacza \"odważny\", \"odważne\" lub \"odważna\". Nazwa może odnosić się do: Fatos Arapi (1930-2018), albanian poet Fatos Beja (ur. 1948), albanian polityk Fatos Bećiraj (ur. 1988), albanian-Montenegrin piłkarz Fatos Daja (ur., 1968), albanian piłkarza Fatos Hoxha (ur. 1961), albanian politician Fatos Kongoli (ur. 1944), albanian pisarz Fatos Lala (ur. 1995), albanian futbolist Fatos Lubonja ...</p>", "Faical": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Faycal</b>.</p><p>Faisal, Faisel, Fayçal lub Faysal (arabski: فيصل) to arabskie imię. Faisal, Fayçal lub Faysal mogą również odnosić się do:</p>", "Fernando Jose": "<p>Fernando Jose to męskie imię. Znani ludzie z imieniem to: Fernando José de França Dias Van-Dúnem (ur. 1934), angolański polityk Fernando José Torres Sanz, Fernando Torres Fernando José (aktor), brazylijczy aktor</p>", "Fredy Alexander": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fredy</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fredi</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fred</b>.</p><p>August Frederick ⁇ Fred\" Kammer Jr.; 3 czerwca 1912, Brooklyn - 21 lutego 1996, Hob-Sound) - amerykański hokejista i golfa, brązowy zwycięzca zimowych igrzysk olimpijskich 1936.</p>", "Fredi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fred</b>.</p><p>August Frederick ⁇ Fred\" Kammer Jr.; 3 czerwca 1912, Brooklyn - 21 lutego 1996, Hob-Sound) - amerykański hokejista i golfa, brązowy zwycięzca zimowych igrzysk olimpijskich 1936.</p>", "Fadhel": "<p>Fazel w perskim lub Fadhel (arabski: فاضل) to arabskie i perskie imię męskie i nazwisko oznaczające \"oddzielne\". Może odnosić się do: Michaela Fadela (1710-1795), maronitskiego patriarchy Antiochii Fazela Darbandi (zmarł 1869/70), irańskiego szhiackiego duchownego i uczonego Mustafa Fazl Paszy (1830-1875), osmańskiego egipskiego księcia Muhammada Fadhela al-Jamali (1903-1997), irackiego polityka Fazıl Küçük (1906-1984), wiceprezydenta Republiki Cypryjskiej Mounir Abou ...</p>", "Fergal": "<p>Fergal lub Feargal to irlandzkie nazwiska męskie. Są angliczowanymi formami nazwy Fearghal.</p>", "Frane": "<p>Frane to męskie chorwackie imię i wariant Franciscus. Do wybitnych osób z tym nazwiskiem należą: Frane Adam (ur. 1948), słoweński socjolog, redaktor i były dysydent polityczny aktywista Frane Bitunjac (ur. 1997), chorwacki piłkarz Frane Bućan (ur. 1965), chorwackie piłkarze Frane Bulić (1846-1934), chorwański kapłan, archeolog i historyk Frane Čačić (ur. 1980), chorwacki piłkarzek Frane Čirjak (ur. 1995), chorwa...</p>", "Filaret": "<b>Filaret</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, którego patronem jest św. Filaret, zwany Kalabryjczykiem (<a href=\"https://pl.wikipedia.org/wiki/XI_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XI wiek</a>).", "Farouq": "<p>Farooq (tzw. Farouk, Faroqi, Farook, Faruk, Faroeq, Faruq, Farooqi, Farooqui, Farooque lub Farooqui; arabski: فاروق, romanized: Fārūq) to powszechne arabskie imię i nazwisko. Al-Fārūq dosłownie oznacza \"tego, który rozróżnia między dobrym a złem\".</p>", "Fisnik": "<p>Fisnik to albanianki męski imię, co oznacza \"szlachetny\". Nazwa może odnosić się do: Fisnik Asllani (ur. 2002), niemiecki piłkarz piłkarza albanii Fisnik Maxville, kosowsko-szwajcarskiego filmowca Fisnika Papuçi (ur. 1983), kosowskiego piłkarze piłkarzy albanii Fisnika Rugova (ur. 1989), kosowskiego piłkarka koszykówki albanii Fisniku Zuka (ur. 1995), makedonii-albaniackiego piłkara</p>", "Farbod": "<p>Farbod (persk: فربد) to perskie imię, które oznacza \"ochroniarza chwały\". Nazwa ta pochodzi z czasów przed muzułmańskim podbojem Persji, kiedy Imperium Perskie przyjęło swoją starożytną religię, zoroastryzm.</p>", "Feres": "<b>Feres</b> (gr. <i>Phéres</i>) − postać w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii greckiej</a>. Był synem <a href=\"https://pl.wikipedia.org/wiki/Kreteus\" target=\"_blank\" rel=\"noopener noreferrer\">Kreteusa</a> i <a href=\"https://pl.wikipedia.org/wiki/Tyro\" target=\"_blank\" rel=\"noopener noreferrer\">Tyro</a> oraz ojcem <a href=\"https://pl.wikipedia.org/wiki/Admet\" target=\"_blank\" rel=\"noopener noreferrer\">Admeta</a>. Założył miasto <a href=\"https://pl.wikipedia.org/wiki/Feraj\" target=\"_blank\" rel=\"noopener noreferrer\">Feraj</a> w <a href=\"https://pl.wikipedia.org/wiki/Tesalia\" target=\"_blank\" rel=\"noopener noreferrer\">Tesalii</a>, którego nazwa pochodzi także od jego imienia. Będąc już bardzo starym, nie chciał spełnić prośby syna, gdy ten szukał kogoś, kto zgodziłby się za niego umrzeć.", "Friedemann": "<p>Friedemann to niemieckie imię, które oznacza \"człowiek pokoju\". Wilhelm Friedemann Bach, niemiecki kompozytor i najstarszy syn Joanna Sebastiana Bach Friedemana Friese, niemiecka gracza planszowego Friedemana Schulza von Thuna, niemiecko psychologa Friedemana (nazwa) Nancy Friedemann-Sánchez, kolumbijsko-amerykańskiego artysty wizualnego z siedzibą w Lincoln w stanie Nebraska.</p>", "Fabian Enrique": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Fabian</b>.</p><b>Fabian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „należący do Fabiusza” (mężczyzny z rodu Fabiuszów). Nazwa rodowa Fabiuszy wywodzi się zaś od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>faba</em> (<a href=\"https://pl.wikipedia.org/wiki/B%C3%B3b\" target=\"_blank\" rel=\"noopener noreferrer\">bób</a>) i pierwotnie oznaczała osobę zajmującą się uprawą bobu. Chrześcijańskim patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Fabian_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Fabian, papież</a>.", "Fabian Alberto": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Fabian</b>.</p><b>Fabian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „należący do Fabiusza” (mężczyzny z rodu Fabiuszów). Nazwa rodowa Fabiuszy wywodzi się zaś od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>faba</em> (<a href=\"https://pl.wikipedia.org/wiki/B%C3%B3b\" target=\"_blank\" rel=\"noopener noreferrer\">bób</a>) i pierwotnie oznaczała osobę zajmującą się uprawą bobu. Chrześcijańskim patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Fabian_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Fabian, papież</a>.", "Farshid": "<p>Farshid (lub Farsheed) to perskie imię. Składa się z dwóch morfemi, daleko (światło, blask) + shîd (słońce, promienie słoneczne).</p>", "Felix Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Felix</b>.</p><p>Felix (lat. Felix - ⁇ płodny, owocny, szczęśliwy, dobrobytny, błogosławiony, bogaty) - imię męskie.</p>", "Ferman": "<b>Firman</b> – w dawnych państwach <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmańskich</a> określenie oficjalnych dokumentów wystawianych przez władcę (<a href=\"https://pl.wikipedia.org/wiki/Su%C5%82tan\" target=\"_blank\" rel=\"noopener noreferrer\">sułtana</a>). Firman zawierał osobisty pisemny rozkaz i był pieczętowany sułtańską pieczęcią. Słowo pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">perskiego</a> słowa <i>farmân</i> (فرمان), znaczącego <i>dekret</i> lub <i>nakaz</i>. W sułtańskiej Turcji używana była forma <i>ferman</i>.", "Franciszek Józef": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Franciszek</b>.</p><b>Franciszek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie wywodzące się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a> określenia <i>francesco</i> oznaczającego \"Francuza, Francuzika\", jakim kupiec Piotr Bernardone (ojciec <a href=\"https://pl.wikipedia.org/wiki/Franciszek_z_Asy%C5%BCu\" target=\"_blank\" rel=\"noopener noreferrer\">św. Franciszka z Asyżu</a>) nazwał swego syna Jana, gdy ten wrócił z Francji. W Asyżu zaczęto powszechnie nazywać chłopca tym określeniem i pod takim imieniem znany jest powszechnie.", "Felicjano": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Felicjan</b>.</p><b>Felicjan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, powstałe jako przydomek od imienia <a href=\"https://pl.wikipedia.org/wiki/Feliks\" target=\"_blank\" rel=\"noopener noreferrer\">Feliks</a> i bliźniacze do niego znaczeniowo. <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%9Bci%C3%B3%C5%82_katolicki\" target=\"_blank\" rel=\"noopener noreferrer\">Kościół katolicki</a> notuje licznych świętych o tym imieniu.", "Frédérick": "<p>Frédéric i Frédérick są francuską wersją powszechnego męskiego nazwiska Frederick. W artystyce: Frédéric Back, kanadyjski nagradzany animator Frédéric Bartholdi, francuski rzeźbiarz Frédéric Bazille, malarz impresjonistyczny, najbardziej znany ze swoich obrazków postaci Frédéric Mariotti, aktor W polityce: Frédérique Bamvuginyumvira, 1 wiceprezes Burundi Frédéric Ngenzebuhoro, wiceprezesa Burundi od 11 listopada...</p>", "Faruq": "<p>Farooq (tzw. Farouk, Faroqi, Farook, Faruk, Faroeq, Faruq, Farooqi, Farooqui, Farooque lub Farooqui; arabski: فاروق, romanized: Fārūq) to powszechne arabskie imię i nazwisko. Al-Fārūq dosłownie oznacza \"tego, który rozróżnia między dobrym a złem\".</p>", "Feofan": "<p>Feofan lub Theophan to męskie imię. Może odnosić się do: Feofan Davitaia (1911-1979), gruziński geograf Theophan Bystrov (1875-1940), rosyjski arcybiskup Theophan Prokopovich (1681-1736), rosyjskiego teologa</p>", "Farys": "<b>Farys</b> – <a href=\"https://pl.wikipedia.org/wiki/Muzu%C5%82manin\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmański</a> <a href=\"https://pl.wikipedia.org/wiki/Je%C5%BAdziec\" target=\"_blank\" rel=\"noopener noreferrer\">jeździec</a>, profesjonalny <a href=\"https://pl.wikipedia.org/wiki/Wojownik\" target=\"_blank\" rel=\"noopener noreferrer\">wojownik</a> (<a href=\"https://pl.wikipedia.org/wiki/Mamelucy\" target=\"_blank\" rel=\"noopener noreferrer\">mameluk</a>), wojownik–niewolnik <a href=\"https://pl.wikipedia.org/wiki/Ghilman\" target=\"_blank\" rel=\"noopener noreferrer\">ghilman</a>, odpowiednik europejskiego <a href=\"https://pl.wikipedia.org/wiki/Rycerstwo\" target=\"_blank\" rel=\"noopener noreferrer\">rycerza</a>. Samo słowo w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">języku arabskim</a> oznaczało jeźdźca (Nicolle, Saracen Faris, strona 3). Uzbrojony w następujące rodzaje broni (choć nie we wszystkie naraz): <a href=\"https://pl.wikipedia.org/wiki/%C5%81uk_(bro%C5%84)\" target=\"_blank\" rel=\"noopener noreferrer\">łuk</a>, <a href=\"https://pl.wikipedia.org/wiki/Miecz\" target=\"_blank\" rel=\"noopener noreferrer\">miecz</a>, <a href=\"https://pl.wikipedia.org/wiki/Szabla\" target=\"_blank\" rel=\"noopener noreferrer\">szablę</a>, <a href=\"https://pl.wikipedia.org/wiki/W%C5%82%C3%B3cznia\" target=\"_blank\" rel=\"noopener noreferrer\">włócznię</a>, <a href=\"https://pl.wikipedia.org/wiki/Oszczep_(bro%C5%84)\" target=\"_blank\" rel=\"noopener noreferrer\">oszczep</a>, <a href=\"https://pl.wikipedia.org/wiki/Top%C3%B3r\" target=\"_blank\" rel=\"noopener noreferrer\">topór</a> (<i>tabarzin</i>), <a href=\"https://pl.wikipedia.org/wiki/Czekan_(bro%C5%84)\" target=\"_blank\" rel=\"noopener noreferrer\">czekan</a>, <a href=\"https://pl.wikipedia.org/wiki/Nadziak\" target=\"_blank\" rel=\"noopener noreferrer\">nadziak</a>, <a href=\"https://pl.wikipedia.org/wiki/Kopia_(bro%C5%84)\" target=\"_blank\" rel=\"noopener noreferrer\">kopię</a>, <a href=\"https://pl.wikipedia.org/wiki/Maczuga_(bro%C5%84)\" target=\"_blank\" rel=\"noopener noreferrer\">maczugę</a> – sztukę posługiwania się tym <a href=\"https://pl.wikipedia.org/wiki/Bro%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">orężem</a> zwaną <i>furusiya</i> ćwiczono w <a href=\"https://pl.wikipedia.org/wiki/Koszary\" target=\"_blank\" rel=\"noopener noreferrer\">koszarach</a>, na <a href=\"https://pl.wikipedia.org/wiki/Majdan_(urbanistyka)\" target=\"_blank\" rel=\"noopener noreferrer\">majdanie</a> jak i podczas <a href=\"https://pl.wikipedia.org/wiki/Polowanie\" target=\"_blank\" rel=\"noopener noreferrer\">polowania</a> na dzikie zwierzęta. Ale furusiya to nie tylko walka bronią, ale również jazda konna, zapasy, musztra, strzelanie z kuszy, <a href=\"https://pl.wikipedia.org/wiki/Polo_(sport)\" target=\"_blank\" rel=\"noopener noreferrer\">polo</a>, wyścigi konne, walka piesza z bronią, posłuszeństwo, nauka taktyki i strategii, posiadanie dobrej jakości broni oraz pancerza, wytrwałość i zwinność (Nicolle, strona 8-9). Według <i>Siyast Nama</i> trening farysa zabierał 8 lat, i był stopniowany co do użycia broni, konia i pancerza, a także obowiązków i pozycji farysa (Nicolle, strona 10). Wojownicy muzułmańscy nosili długie włosy i wąsy w odróżnieniu od populacji cywilnej (Nicolle, Saracen Faris, strona 5). W oddziałach <a href=\"https://pl.wikipedia.org/wiki/Jazda\" target=\"_blank\" rel=\"noopener noreferrer\">kawalerii</a> złożonych z farysów służyli <a href=\"https://pl.wikipedia.org/wiki/Turcy\" target=\"_blank\" rel=\"noopener noreferrer\">Turcy</a>, <a href=\"https://pl.wikipedia.org/wiki/Ormianie\" target=\"_blank\" rel=\"noopener noreferrer\">Ormianie</a>, <a href=\"https://pl.wikipedia.org/wiki/Kurdowie\" target=\"_blank\" rel=\"noopener noreferrer\">Kurdowie</a>, <a href=\"https://pl.wikipedia.org/wiki/Grecy\" target=\"_blank\" rel=\"noopener noreferrer\">Grecy</a>, <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">Słowianie</a>, <a href=\"https://pl.wikipedia.org/wiki/Ludy_ira%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Irańczycy</a> (<a href=\"https://pl.wikipedia.org/wiki/Persowie\" target=\"_blank\" rel=\"noopener noreferrer\">Persowie</a>) i <a href=\"https://pl.wikipedia.org/wiki/Arabowie\" target=\"_blank\" rel=\"noopener noreferrer\">Arabowie</a>. Słynnym <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowiecznym</a> farysem był <a href=\"https://pl.wikipedia.org/wiki/Usama_Ibn_Munkiz\" target=\"_blank\" rel=\"noopener noreferrer\">Usama Ibn Munkiz</a>, który pozostawił po sobie pamiętnik \"Kitab al-itibar\".", "Frankline": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Franklin</b>.</p><p>James Franklin (około 1783 - 31 sierpnia 1834) - brytyjski żołnierz i naturalista.</p>", "Franciszek Jan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Franciszek</b>.</p><b>Franciszek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie wywodzące się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a> określenia <i>francesco</i> oznaczającego \"Francuza, Francuzika\", jakim kupiec Piotr Bernardone (ojciec <a href=\"https://pl.wikipedia.org/wiki/Franciszek_z_Asy%C5%BCu\" target=\"_blank\" rel=\"noopener noreferrer\">św. Franciszka z Asyżu</a>) nazwał swego syna Jana, gdy ten wrócił z Francji. W Asyżu zaczęto powszechnie nazywać chłopca tym określeniem i pod takim imieniem znany jest powszechnie.", "Fredric": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fredrik</b>.</p><p>Fredrik - szwedzka indy-grupa z Malmów, Szwecja. Jej uczestnikami byli Fredrik Haltin, Ola Lindelfelt i Anna Moberg.</p>", "Fazlul": "<p>Fazl (arabski: فضل) to arabskie słowo oznaczające łaskę lub cnótę. Może być również przetłumaczana jako Fadl lub z dodaniem dodatkowej vokalu.</p>", "Florentino Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florentino</b>.</p><p>Florentino to zarówno męskie imię, jak i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Florin-Daniel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Fabian Camilo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Fabian</b>.</p><b>Fabian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „należący do Fabiusza” (mężczyzny z rodu Fabiuszów). Nazwa rodowa Fabiuszy wywodzi się zaś od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>faba</em> (<a href=\"https://pl.wikipedia.org/wiki/B%C3%B3b\" target=\"_blank\" rel=\"noopener noreferrer\">bób</a>) i pierwotnie oznaczała osobę zajmującą się uprawą bobu. Chrześcijańskim patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Fabian_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Fabian, papież</a>.", "Francisco De Asis": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Francisco</b>.</p><p>Francisco (hisp. Francisco) - hiszpańskie imię i nazwisko męskie, w innych językach występują warianty - Francisco, Francesco, Francisc.</p>", "Fernando Andres": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Fernando</b>.</p><p>Fernando: Fernando - hiszpańskie imię i nazwisko Fernando - skrócenie botaniczne, które oznacza, że autorem taksy jest Edwin Fernando.  ⁇ Fernando ⁇ - singel ze zespołu ABBA.</p>", "Fernando Enrique": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Fernando</b>.</p><p>Fernando: Fernando - hiszpańskie imię i nazwisko Fernando - skrócenie botaniczne, które oznacza, że autorem taksy jest Edwin Fernando.  ⁇ Fernando ⁇ - singel ze zespołu ABBA.</p>", "Frieder": "<p>Frieder jest zarówno nazwiskiem jak i męskim nazwiskiem, wariantem Friedrich. Mieszkańcy nazwiska: Imię przesiadkowe: Armin Frieder (1911-1946), słowacki rabin Neolog Bill Frieder (1942), były trener koszykówki Katalin Frieder (1915-1991), węgierski pianista Imię przeniesiony: Frieder Bernius (1947), niemiecki dyrygent Frieder Birzele (1940-2023), niemiecka polityk Frieder Burda (1936-2019), niemiecki kolekcjoner sztuki Frieder Gröger (1934-2018), niemiecki...</p>", "Farook": "<p>Farooq (tzw. Farouk, Faroqi, Farook, Faruk, Faroeq, Faruq, Farooqi, Farooqui, Farooque lub Farooqui; arabski: فاروق, romanized: Fārūq) to powszechne arabskie imię i nazwisko. Al-Fārūq dosłownie oznacza \"tego, który rozróżnia między dobrym a złem\".</p>", "Fredie": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fredi</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fred</b>.</p><p>August Frederick ⁇ Fred\" Kammer Jr.; 3 czerwca 1912, Brooklyn - 21 lutego 1996, Hob-Sound) - amerykański hokejista i golfa, brązowy zwycięzca zimowych igrzysk olimpijskich 1936.</p>", "Fawwaz": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fawaz</b>.</p><p>Fawaz (czasami Fawwaz lub Fawez) jest męskim arabskim nazwiskiem i nazwiskiem. Dosłowne znaczenie tego słowa jest \"wygrywający\", ponieważ jest to przymiotnik męski z czasownika faz fāz, co oznacza \"wygrał\".</p>", "Franciszek Antoni": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Franciszek</b>.</p><b>Franciszek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie wywodzące się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a> określenia <i>francesco</i> oznaczającego \"Francuza, Francuzika\", jakim kupiec Piotr Bernardone (ojciec <a href=\"https://pl.wikipedia.org/wiki/Franciszek_z_Asy%C5%BCu\" target=\"_blank\" rel=\"noopener noreferrer\">św. Franciszka z Asyżu</a>) nazwał swego syna Jana, gdy ten wrócił z Francji. W Asyżu zaczęto powszechnie nazywać chłopca tym określeniem i pod takim imieniem znany jest powszechnie.", "Francisco De Borja": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Francisco</b>.</p><p>Francisco (hisp. Francisco) - hiszpańskie imię i nazwisko męskie, w innych językach występują warianty - Francisco, Francesco, Francisc.</p>", "Ferdie": "<p>Ferdy lub Ferdie to imię, często diminutiw męskiego imienia Ferdinand. Może odnosić się do:</p>", "Fattah": "<p>Fattah (فتاح, Fattāḥ) może odnosić się do: al-Fattāḥ, jednego z imion Boga w islamie, i tłumaczy się na \"otwierający\" lub \"dający zwycięstwo\"</p>", "Franciszek Andrzej": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Franciszek</b>.</p><b>Franciszek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie wywodzące się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a> określenia <i>francesco</i> oznaczającego \"Francuza, Francuzika\", jakim kupiec Piotr Bernardone (ojciec <a href=\"https://pl.wikipedia.org/wiki/Franciszek_z_Asy%C5%BCu\" target=\"_blank\" rel=\"noopener noreferrer\">św. Franciszka z Asyżu</a>) nazwał swego syna Jana, gdy ten wrócił z Francji. W Asyżu zaczęto powszechnie nazywać chłopca tym określeniem i pod takim imieniem znany jest powszechnie.", "Florin-Mihai": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Farah": "<p>Farah jest miastem i nagar panchayatem mathura w stanie uttar pradesh w india.</p>", "Felicien": "<p>Félicien lub Felicien to imię. Wśród znanych osób z tej nazwy są: Félicien Du Bois (ur. 1983), szwajcarski profesjonalny defensywany hokeja na lodzie Félicien Cattier (1869-1946), bardzo wybitny belgijski bankier, finansista i filantrop Félicien Champsaur (1858-1934), francuski pisarz i dziennikarz Félicien Chapuis (1824-1879), belgijski lekarz i entomolog Félicien Courbet (1888-1967), belgijski piłkarz wodny i pływacz piersiowy...</p>", "Florin-Cristian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Fredy Alejandro": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fredy</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fredi</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fred</b>.</p><p>August Frederick ⁇ Fred\" Kammer Jr.; 3 czerwca 1912, Brooklyn - 21 lutego 1996, Hob-Sound) - amerykański hokejista i golfa, brązowy zwycięzca zimowych igrzysk olimpijskich 1936.</p>", "Fayzali": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Faizali</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Faizal</b>.</p><p>Faizal to męskie imię. Jest również używane jako nazwisko.</p>", "Fauzan": "<p>Fouzan, zwanego również Fawzan, Fowzan i Fauzan, jest arabską nazwą oznaczającą \"udany\", \"udany,\" \"wygrywający\" lub \"wygrywca\". W języku arabskim istnieje jedno i wiele czasowych, a także podwójne czasowe.</p>", "Federiko": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Federico</b>.</p><p>Fredericko (włoski)  Federico, ok.</p>", "Fazail": "<p>Fazail to męskie imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Faro": "<b>Faro</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, od germ. <i>fara</i> – \"podróż\". Patronem tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Faro_z_Meaux\" target=\"_blank\" rel=\"noopener noreferrer\">Faro</a>, biskup <a href=\"https://pl.wikipedia.org/wiki/Meaux\" target=\"_blank\" rel=\"noopener noreferrer\">Meaux</a> (<a href=\"https://pl.wikipedia.org/wiki/VII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VII wiek</a>).", "Fredryk": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fredrik</b>.</p><p>Fredrik - szwedzka indy-grupa z Malmów, Szwecja. Jej uczestnikami byli Fredrik Haltin, Ola Lindelfelt i Anna Moberg.</p>", "Francisco Jr": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Francisco</b>.</p><p>Francisco (hisp. Francisco) - hiszpańskie imię i nazwisko męskie, w innych językach występują warianty - Francisco, Francesco, Francisc.</p>", "France": "<p>Francja (francuski France, MFA:), oficjalna nazwa - Francuska Republika (francuska Rzeczpospolitej).</p>", "Fernando Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Fernando</b>.</p><p>Fernando: Fernando - hiszpańskie imię i nazwisko Fernando - skrócenie botaniczne, które oznacza, że autorem taksy jest Edwin Fernando.  ⁇ Fernando ⁇ - singel ze zespołu ABBA.</p>", "Fabian Eduardo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Fabian</b>.</p><b>Fabian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „należący do Fabiusza” (mężczyzny z rodu Fabiuszów). Nazwa rodowa Fabiuszy wywodzi się zaś od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>faba</em> (<a href=\"https://pl.wikipedia.org/wiki/B%C3%B3b\" target=\"_blank\" rel=\"noopener noreferrer\">bób</a>) i pierwotnie oznaczała osobę zajmującą się uprawą bobu. Chrześcijańskim patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Fabian_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Fabian, papież</a>.", "Fekri": "<p>Fikri (arabsko: فِكْرِي fik·riy, fik·rī, fik·ry) również pisowany jako Fekri, jest męskim nazwiskiem arabskim lub nazwiskiem w formie posiadłości, co zwykle oznacza \"myślny\", ale może również oznaczać \"intelektualnie, psychicznie, duchowo\". Może odnosić się do:</p>", "Fardeen": "<p>Fardeen lub Fardin to męskie imię pochodzące z perskich języków, co oznacza \"światłowy\" i \"który ma trzykrotną siłę\". Jest to również alternatywna nazwa miesiąca Farvardin.</p>", "Fredo": "<p>Fredo jest męskim imieniem i diminutiwem Alfreda lub Federico, które może odnosić się do:</p>", "Fernando Antonio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Fernando</b>.</p><p>Fernando: Fernando - hiszpańskie imię i nazwisko Fernando - skrócenie botaniczne, które oznacza, że autorem taksy jest Edwin Fernando.  ⁇ Fernando ⁇ - singel ze zespołu ABBA.</p>", "Florin-Cosmin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Florin-Gabriel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Francisco Antonio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Francisco</b>.</p><p>Francisco (hisp. Francisco) - hiszpańskie imię i nazwisko męskie, w innych językach występują warianty - Francisco, Francesco, Francisc.</p>", "Florijan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Florian</b>.</p><b>Florian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego „kwitnący kwiat”. W Polsce używane bywało w formie <b>Tworzyjan</b>. Od Floriana wywodzi się także czeski neologizm <i>Květoslav</i>.", "Francisco José": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Francisco</b>.</p><p>Francisco (hisp. Francisco) - hiszpańskie imię i nazwisko męskie, w innych językach występują warianty - Francisco, Francesco, Francisc.</p>", "Florin-Mircea": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Frithjof": "<p>Friðþjófur (variaty: Fritiof, Frithiof, Frigjof, Frithjof i Fridtjof) to skandynawskie męskie imię pochodzące z starożytnego norweskiego: friðr + þjófr, tłumaczenie. \"Pokój\" i \"kradłak\".</p>", "Florin-Adrian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Florin-Ioan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Feyruz": "<p>Fayrūz (arabsko: فيروز, lit. 'Turkizowy'), różnie przetłumaczony jako Feyrouz, Fayrouz, Fairuz, Fairooz, Fayruz itp., jest arabskim nazwiskiem dla kobiet i mężczyzn.</p>", "Frank-Peter": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Frank</b>.</p><p>Frank - debiutancki album studiowy brytyjskiej piosenkarki Amy Winehouse, wydany 20 października 2003 roku przez Island Records. Album zajął trzynaste miejsce w brytyjskich listach.</p>", "Francois-Xavier": "<p>François-Xavier to francuskie męskie imię. Do wybitnych osób z tym nazwiskiem należą: François-Xavier Archambault (1841-1893), prawnik i polityczna postać w Quebecu François-Xavié Audouin (1765-1837), francuski duchowny i polityk podczas rewolucji francuskiej François-Xavie Babineau (1825-1890), kanadyjski kapłan katolicki François-Xavio Bélanger (1833-1882), francusko-kanadyjski naturalista i kurator muzeów François-Xavia Bellamy ...</p>", "Faizullah": "<p>Faizullah, również pisany jako Fayzullah lub Feizollah (arabsko: فيض الله) to męskie muzułmańskie imię, składające się z elementów Faiz i Allah. To znaczy sukces od Boga lub zwycięstwo od Boga.</p>", "Florenty": "<b>Florencjusz</b>, <b>Florenty</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, występujące w Polsce już w <a href=\"https://pl.wikipedia.org/wiki/XII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XII wieku</a> (<a href=\"https://pl.wikipedia.org/wiki/1175\" target=\"_blank\" rel=\"noopener noreferrer\">1175</a> r.). Powstało ono od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomka</a> <i>Florentius</i>, utworzonego poprzez dodanie <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostka</a> <i>-ius</i> od innego przydomka, <i>Florens</i> (łac. <i>florens</i>, <i>-ntis</i> — \"kwitnący\"). Istnieją liczni święci patroni tego imienia (nawet dwudziestu), m.in. św. <a href=\"https://pl.wikipedia.org/wiki/Florencjusz_z_Populonii\" target=\"_blank\" rel=\"noopener noreferrer\">Florencjusz z Populonii</a>, biskup (<a href=\"https://pl.wikipedia.org/wiki/IV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">IV wiek</a>).", "Faustin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Faustyn</b>.</p><b>Faustyn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od rzymskiego nazwiska <i>Faustinus</i>, które pierwotnie oznaczało „pochodzący od <a href=\"https://pl.wikipedia.org/wiki/Faust_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Fausta</a>, należący do Fausta”. Imię to nosiło wielu świętych, a jednym ze znanych jest św. Faustyn, wspominany 15 lutego ze swoim bratem, św. <a href=\"https://pl.wikipedia.org/wiki/Jowita\" target=\"_blank\" rel=\"noopener noreferrer\">Jowitą</a>. Łacińska grupa, od której imię to pochodzi (<i>faustus</i> — „błogi, pomyślny”, ale także <i>faveo, favi, fautum</i> — „sprzyjać, być przychylnym”) nie ma pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_indoeuropejskie\" target=\"_blank\" rel=\"noopener noreferrer\">indoeuropejskiego</a> oraz pewnych odpowiedników w żadnym języku indoeuropejskim.", "Fabian Arley": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Fabian</b>.</p><b>Fabian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „należący do Fabiusza” (mężczyzny z rodu Fabiuszów). Nazwa rodowa Fabiuszy wywodzi się zaś od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>faba</em> (<a href=\"https://pl.wikipedia.org/wiki/B%C3%B3b\" target=\"_blank\" rel=\"noopener noreferrer\">bób</a>) i pierwotnie oznaczała osobę zajmującą się uprawą bobu. Chrześcijańskim patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Fabian_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Fabian, papież</a>.", "Felin": "<b>Felin</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, którego patronem jest św. Felin, towarzysz św. Gratyniana i razem z nim patron <a href=\"https://pl.wikipedia.org/wiki/Arona_(W%C5%82ochy)\" target=\"_blank\" rel=\"noopener noreferrer\">Arony</a>. <a href=\"https://pl.wikipedia.org/wiki/Gratynian_i_Felin\" target=\"_blank\" rel=\"noopener noreferrer\">Gratynian i Felin</a> zostali męczennikami za czasów cesarza <a href=\"https://pl.wikipedia.org/wiki/Trajan_Decjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Decjusza</a>. Relikwie przeniesiono do <a href=\"https://pl.wikipedia.org/wiki/Opactwo\" target=\"_blank\" rel=\"noopener noreferrer\">opactwa</a> w Aronie, gdzie opatem–komendatariuszem był w <a href=\"https://pl.wikipedia.org/wiki/1550\" target=\"_blank\" rel=\"noopener noreferrer\">1550</a> <a href=\"https://pl.wikipedia.org/wiki/Karol_Boromeusz\" target=\"_blank\" rel=\"noopener noreferrer\">Karol Boromeusz</a>. Obecnie opactwo jest zlikwidowane, ale kościół pod wezwaniem męczenników istnieje po dziś dzień.", "Fedot": "<p>Fedot (rosyjski: Федот, stara ortografia: ⁇ едотъ) to męska rosyjska forma nazwiska Theodotus (grecki: Θεόδοτος). Należy pamiętać, że rosyjski rymowany przysłowiec: Федот да не тот, Fedot da ne tot, 'Fedot, ale zły jeden', powiedział o kimś, kto jest inny niż oczekiwano lub gorszy niż udaje, że jest.</p>", "François Paul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>François</b>.</p><p>François (francuski) - francuskie imię i nazwisko mężczyzn (włoski - Francuasa).</p>", "Farial": "<p>Faryal (persk. فریال Faryâl; arabski: فَرْيَال Faryāl; azerbaińskie: Fəryal; tajczyckie: Фарёл, romanized: Faryol; tureckie: Feryal; urdu: فریال Fareāl; uzb. Jest to połączenie perskiego słowa فر (far) oznaczające \"wielkość\" i yal (yâl) oznaczające 'ganek'.</p>", "Fumio": "<b>Fumio</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;ふみお, フミオ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Fakhruddin": "<p>Fakhr al-Din (arabski: فخر الدين) to arabskie imię męskie i (w współczesnym użyciu) nazwisko, co oznacza honor / dumę religii. Alternatywne transliteracje obejmują Fachreddin, Fakhreddine, Fahrettin, Fakraddin, Fakhhreddin, Fahruddin, Fexredîn itp.</p>", "Filip-David": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Filip</b>.</p>Nosił je np. <a href=\"https://pl.wikipedia.org/wiki/Filip_II_Macedo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Filip II Macedoński</a>, ojciec <a href=\"https://pl.wikipedia.org/wiki/Aleksander_Macedo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksandra Wielkiego</a>. Żeńskie odpowiedniki tego imienia to <a href=\"https://pl.wikipedia.org/wiki/Filipina\" target=\"_blank\" rel=\"noopener noreferrer\">Filipina</a>, <a href=\"https://pl.wikipedia.org/wiki/Filipa\" target=\"_blank\" rel=\"noopener noreferrer\">Filipa</a>. Nazwiska pochodzące od Filipa: <a href=\"https://pl.wikipedia.org/wiki/Filipowicz\" target=\"_blank\" rel=\"noopener noreferrer\">Filipowicz</a>, Filipczak, Filipek, Filipowski, Filipkowski. Nazwa państwa <a href=\"https://pl.wikipedia.org/wiki/Filipiny\" target=\"_blank\" rel=\"noopener noreferrer\">Filipiny</a> pochodzi od imienia króla Hiszpanii <a href=\"https://pl.wikipedia.org/wiki/Filip_II_Habsburg\" target=\"_blank\" rel=\"noopener noreferrer\">Filipa II Habsburga</a>.", "Flor": "<p>Gustav August Adam Flor (niem. Gustav August Flor; 1829 - 1883) - rosyjski entomolog, niemiecki bałtycki.</p>", "Franciszek Piotr": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Franciszek</b>.</p><b>Franciszek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie wywodzące się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a> określenia <i>francesco</i> oznaczającego \"Francuza, Francuzika\", jakim kupiec Piotr Bernardone (ojciec <a href=\"https://pl.wikipedia.org/wiki/Franciszek_z_Asy%C5%BCu\" target=\"_blank\" rel=\"noopener noreferrer\">św. Franciszka z Asyżu</a>) nazwał swego syna Jana, gdy ten wrócił z Francji. W Asyżu zaczęto powszechnie nazywać chłopca tym określeniem i pod takim imieniem znany jest powszechnie.", "Fernando Miguel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Fernando</b>.</p><p>Fernando: Fernando - hiszpańskie imię i nazwisko Fernando - skrócenie botaniczne, które oznacza, że autorem taksy jest Edwin Fernando.  ⁇ Fernando ⁇ - singel ze zespołu ABBA.</p>", "Franki": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Franky</b>.</p><p>Frankie lub Franky mogą odnosić się do:</p>", "Frances": "<p>Francis (ang. Francis, Francys, Frances) - nazwa i nazwisko w krajach angiologogich.</p>", "Fabian De Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Fabian</b>.</p><b>Fabian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „należący do Fabiusza” (mężczyzny z rodu Fabiuszów). Nazwa rodowa Fabiuszy wywodzi się zaś od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>faba</em> (<a href=\"https://pl.wikipedia.org/wiki/B%C3%B3b\" target=\"_blank\" rel=\"noopener noreferrer\">bób</a>) i pierwotnie oznaczała osobę zajmującą się uprawą bobu. Chrześcijańskim patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Fabian_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Fabian, papież</a>.", "Ferencz": "<p>Ferenc to imię węgierskiego pochodzenia. Jest krewnym Franciszka, Franciszka, Francesca, François, Franka i Franca.</p>", "Fredy Alonso": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fredy</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fredi</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fred</b>.</p><p>August Frederick ⁇ Fred\" Kammer Jr.; 3 czerwca 1912, Brooklyn - 21 lutego 1996, Hob-Sound) - amerykański hokejista i golfa, brązowy zwycięzca zimowych igrzysk olimpijskich 1936.</p>", "Fredy Andres": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fredy</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fredi</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fred</b>.</p><p>August Frederick ⁇ Fred\" Kammer Jr.; 3 czerwca 1912, Brooklyn - 21 lutego 1996, Hob-Sound) - amerykański hokejista i golfa, brązowy zwycięzca zimowych igrzysk olimpijskich 1936.</p>", "Fabian Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Fabian</b>.</p><b>Fabian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „należący do Fabiusza” (mężczyzny z rodu Fabiuszów). Nazwa rodowa Fabiuszy wywodzi się zaś od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>faba</em> (<a href=\"https://pl.wikipedia.org/wiki/B%C3%B3b\" target=\"_blank\" rel=\"noopener noreferrer\">bób</a>) i pierwotnie oznaczała osobę zajmującą się uprawą bobu. Chrześcijańskim patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Fabian_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Fabian, papież</a>.", "Faiez": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fayez</b>.</p><p>Fayez (arabsko: فَائِز) to arabskie imię dla mężczyzn, wariant Faiz. Mieszkańcy nazwanych Fayez to: Fayez Bandar (ur. 1983), Kuwaicki piłkarz Fayez Ghosn (1950-2021), libański polityk Fayez Sarofim (1929-2022), koptycki egipski amerykański menedżer funduszy Fayez al-Tarawneh (1949-2021), były premier Jordanii</p>", "Florin-Dumitru": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Fabyan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fabian</b>.</p><b>Fabian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „należący do Fabiusza” (mężczyzny z rodu Fabiuszów). Nazwa rodowa Fabiuszy wywodzi się zaś od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>faba</em> (<a href=\"https://pl.wikipedia.org/wiki/B%C3%B3b\" target=\"_blank\" rel=\"noopener noreferrer\">bób</a>) i pierwotnie oznaczała osobę zajmującą się uprawą bobu. Chrześcijańskim patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Fabian_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Fabian, papież</a>.", "Florin-Călin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Francisco Rafael": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Francisco</b>.</p><p>Francisco (hisp. Francisco) - hiszpańskie imię i nazwisko męskie, w innych językach występują warianty - Francisco, Francesco, Francisc.</p>", "Florin-Sebastian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Filipo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Filip</b>.</p>Nosił je np. <a href=\"https://pl.wikipedia.org/wiki/Filip_II_Macedo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Filip II Macedoński</a>, ojciec <a href=\"https://pl.wikipedia.org/wiki/Aleksander_Macedo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksandra Wielkiego</a>. Żeńskie odpowiedniki tego imienia to <a href=\"https://pl.wikipedia.org/wiki/Filipina\" target=\"_blank\" rel=\"noopener noreferrer\">Filipina</a>, <a href=\"https://pl.wikipedia.org/wiki/Filipa\" target=\"_blank\" rel=\"noopener noreferrer\">Filipa</a>. Nazwiska pochodzące od Filipa: <a href=\"https://pl.wikipedia.org/wiki/Filipowicz\" target=\"_blank\" rel=\"noopener noreferrer\">Filipowicz</a>, Filipczak, Filipek, Filipowski, Filipkowski. Nazwa państwa <a href=\"https://pl.wikipedia.org/wiki/Filipiny\" target=\"_blank\" rel=\"noopener noreferrer\">Filipiny</a> pochodzi od imienia króla Hiszpanii <a href=\"https://pl.wikipedia.org/wiki/Filip_II_Habsburg\" target=\"_blank\" rel=\"noopener noreferrer\">Filipa II Habsburga</a>.", "Francisco Alberto": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Francisco</b>.</p><p>Francisco (hisp. Francisco) - hiszpańskie imię i nazwisko męskie, w innych językach występują warianty - Francisco, Francesco, Francisc.</p>", "François Marie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>François</b>.</p><p>François (francuski) - francuskie imię i nazwisko mężczyzn (włoski - Francuasa).</p>", "Fati̇h Mehmet": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Fati̇h</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fatiha</b>.</p><b>Fatiha</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> <b>ﻓﺘﻴﺤﺔ</b>) – arabskie imię żeńskie. Pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Tytu%C5%82_(literaturoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">tytułu</a> pierwszej sury <a href=\"https://pl.wikipedia.org/wiki/Koran\" target=\"_blank\" rel=\"noopener noreferrer\">Koranu</a> <a href=\"https://pl.wikipedia.org/wiki/Al-Fatiha\" target=\"_blank\" rel=\"noopener noreferrer\">Al-Fatihy</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> الفاتحة).", "Florenc": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Florence</b>.</p><p>Florence - własna nazwa; rozpowszechniona w postaci nazwisk.</p>", "Florence": "<p>Florence - własna nazwa; rozpowszechniona w postaci nazwisk.</p>", "Florin-Mădălin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "François Joseph": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>François</b>.</p><p>François (francuski) - francuskie imię i nazwisko mężczyzn (włoski - Francuasa).</p>", "Fazeel": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fazel</b>.</p><p>Fazel w perskim lub Fadhel (arabski: فاضل) to arabskie i perskie imię męskie i nazwisko oznaczające \"oddzielne\". Może odnosić się do: Michaela Fadela (1710-1795), maronitskiego patriarchy Antiochii Fazela Darbandi (zmarł 1869/70), irańskiego szhiackiego duchownego i uczonego Mustafa Fazl Paszy (1830-1875), osmańskiego egipskiego księcia Muhammada Fadhela al-Jamali (1903-1997), irackiego polityka Fazıl Küçük (1906-1984), wiceprezydenta Republiki Cypryjskiej Mounir Abou ...</p>", "Frank David": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Frank</b>.</p><p>Frank - debiutancki album studiowy brytyjskiej piosenkarki Amy Winehouse, wydany 20 października 2003 roku przez Island Records. Album zajął trzynaste miejsce w brytyjskich listach.</p>", "Francisco Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Francisco</b>.</p><p>Francisco (hisp. Francisco) - hiszpańskie imię i nazwisko męskie, w innych językach występują warianty - Francisco, Francesco, Francisc.</p>", "Farès": "<p>Fares lub Farès to męskie imię i nazwisko pochodzenia arabskiego, często wariant Faris. Do wybitnych osób z tym nazwiskiem należą:</p>", "Fulbert": "<b>Fulbert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, o nieznanym znaczeniu. Być może wariant imienia <a href=\"https://pl.wikipedia.org/wiki/Filibert\" target=\"_blank\" rel=\"noopener noreferrer\">Filibert</a>. Patronem tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Fulbert_z_Chartres\" target=\"_blank\" rel=\"noopener noreferrer\">Fulbert</a>, biskup <a href=\"https://pl.wikipedia.org/wiki/Chartres\" target=\"_blank\" rel=\"noopener noreferrer\">Chartres</a> (zm. <a href=\"https://pl.wikipedia.org/wiki/1028\" target=\"_blank\" rel=\"noopener noreferrer\">1028</a>).", "Fuad A": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Fuad</b>.</p><p>Fuad (arabski: َفؤَاد fū\"ād, fou\"ād) (zwany również Fouad, Foud, Fuaad lub Foad) jest męskim arabskim nazwiskiem, co oznacza \"serce\" - bijące się serce, pojęcie \"umysłu i ducha\". Jego pierwotnym słowem jest arabski czasownik fa'ada (arabski: َفَأَد), co oznacza \"palenie lub płomień\", a lahmun fa'eed, co oznacza \"masło pieczone na ognie\".</p>", "Fekry": "<p>Fikri (arabsko: فِكْرِي fik·riy, fik·rī, fik·ry) również pisowany jako Fekri, jest męskim nazwiskiem arabskim lub nazwiskiem w formie posiadłości, co zwykle oznacza \"myślny\", ale może również oznaczać \"intelektualnie, psychicznie, duchowo\". Może odnosić się do:</p>", "Franciszek Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Franciszek</b>.</p><b>Franciszek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie wywodzące się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a> określenia <i>francesco</i> oznaczającego \"Francuza, Francuzika\", jakim kupiec Piotr Bernardone (ojciec <a href=\"https://pl.wikipedia.org/wiki/Franciszek_z_Asy%C5%BCu\" target=\"_blank\" rel=\"noopener noreferrer\">św. Franciszka z Asyżu</a>) nazwał swego syna Jana, gdy ten wrócił z Francji. W Asyżu zaczęto powszechnie nazywać chłopca tym określeniem i pod takim imieniem znany jest powszechnie.", "Friedrich Wilhelm": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Friedrich</b>.</p><p>Hans Christian Friedrich (niem. Hans Christian Friedrich, 1925 - 1992) - niemiecki botanik.</p>", "Florin-Ionut": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Finan": "Istnieją zapiski <a href=\"https://pl.wikipedia.org/wiki/Hagiografia\" target=\"_blank\" rel=\"noopener noreferrer\">hagiograficzne</a> opisujące blisko dziesięć postaci świętych noszących to imię. Jednak nie można zweryfikować historyczności tych postaci gdyż w okresie średniowiecza kopiści, a także późniejsi badacze dopuścili się błędów mieszając imię Finan z imionami Finian, Findian i Fridian. Mimo iż brak źródeł historycznych potwierdzających pochodzenie Finana uważany jest za <a href=\"https://pl.wikipedia.org/wiki/Irlandczycy\" target=\"_blank\" rel=\"noopener noreferrer\">Irlandczyka</a>.", "François-Arnaud": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>François</b>.</p><p>François (francuski) - francuskie imię i nazwisko mężczyzn (włoski - Francuasa).</p>", "Franklin David": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Franklin</b>.</p><p>James Franklin (około 1783 - 31 sierpnia 1834) - brytyjski żołnierz i naturalista.</p>", "Feisal": "<p>Faisal, Faisel, Fayçal lub Faysal (arabski: فيصل) to arabskie imię. Faisal, Fayçal lub Faysal mogą również odnosić się do:</p>", "Felix De Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Felix</b>.</p><p>Felix (lat. Felix - ⁇ płodny, owocny, szczęśliwy, dobrobytny, błogosławiony, bogaty) - imię męskie.</p>", "Fazel": "<p>Fazel w perskim lub Fadhel (arabski: فاضل) to arabskie i perskie imię męskie i nazwisko oznaczające \"oddzielne\". Może odnosić się do: Michaela Fadela (1710-1795), maronitskiego patriarchy Antiochii Fazela Darbandi (zmarł 1869/70), irańskiego szhiackiego duchownego i uczonego Mustafa Fazl Paszy (1830-1875), osmańskiego egipskiego księcia Muhammada Fadhela al-Jamali (1903-1997), irackiego polityka Fazıl Küçük (1906-1984), wiceprezydenta Republiki Cypryjskiej Mounir Abou ...</p>", "Fredy Antonio": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fredy</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fredi</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fred</b>.</p><p>August Frederick ⁇ Fred\" Kammer Jr.; 3 czerwca 1912, Brooklyn - 21 lutego 1996, Hob-Sound) - amerykański hokejista i golfa, brązowy zwycięzca zimowych igrzysk olimpijskich 1936.</p>", "Ferhad": "<p>Ferhat to tureckie imię i to powszechne tureckie pisownianie perskiego imienia Ferhad (perskiego: فرهاد, farhād), chociaż inne pisowni są również używane, ale są znacznie mniej powszechnie. Jest to również arabska nazwa, która jest popularna w krajach Maghreb, a nazwa może pochodzić od słowa \"ferah\", co oznacza \"radość\".</p>", "Faizul": "<p>Faizin (arabski: فیض) to arabskie imię męskie, oznaczające przepływ, obfitość.</p>", "Félicien": "<p>Félicien lub Felicien to imię. Wśród znanych osób z tej nazwy są: Félicien Du Bois (ur. 1983), szwajcarski profesjonalny defensywany hokeja na lodzie Félicien Cattier (1869-1946), bardzo wybitny belgijski bankier, finansista i filantrop Félicien Champsaur (1858-1934), francuski pisarz i dziennikarz Félicien Chapuis (1824-1879), belgijski lekarz i entomolog Félicien Courbet (1888-1967), belgijski piłkarz wodny i pływacz piersiowy...</p>", "Francois D'assise": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>François</b>.</p><p>François (francuski) - francuskie imię i nazwisko mężczyzn (włoski - Francuasa).</p>", "Fama": "Jej <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">greckim</a> odpowiednikiem była <a href=\"https://pl.wikipedia.org/wiki/Feme\" target=\"_blank\" rel=\"noopener noreferrer\">Feme</a>.", "Falkon": "<b>Falkon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, oznaczające \"szlachetność, brawurę, inteligencję\".", "Fransisco": "<p>Francisco to hiszpańska i portugalska forma męskiego nazwiska Franciscus.</p>", "Faizulla": "<p>Faizullah, również pisany jako Fayzullah lub Feizollah (arabsko: فيض الله) to męskie muzułmańskie imię, składające się z elementów Faiz i Allah. To znaczy sukces od Boga lub zwycięstwo od Boga.</p>", "Farzan": "<p>Farzan lub Farzān (perskie: فرزان) to perskie męskie imię lub nazwisko. Kobieta jest Farzaneh/Farzana.</p>", "Feliks Jan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Feliks</b>.</p><b>Feliks</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>felix</em> – łaskawy, szczęśliwy) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Żeńskie odpowiedniki: <a href=\"https://pl.wikipedia.org/wiki/Feliksa\" target=\"_blank\" rel=\"noopener noreferrer\">Feliksa</a>, <a href=\"https://pl.wikipedia.org/wiki/Felicja\" target=\"_blank\" rel=\"noopener noreferrer\">Felicja</a>.", "Francisco Rodrigo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Francisco</b>.</p><p>Francisco (hisp. Francisco) - hiszpańskie imię i nazwisko męskie, w innych językach występują warianty - Francisco, Francesco, Francisc.</p>", "Florin-Andrei": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Francisco Miguel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Francisco</b>.</p><p>Francisco (hisp. Francisco) - hiszpańskie imię i nazwisko męskie, w innych językach występują warianty - Francisco, Francesco, Francisc.</p>", "Fernando Gabriel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Fernando</b>.</p><p>Fernando: Fernando - hiszpańskie imię i nazwisko Fernando - skrócenie botaniczne, które oznacza, że autorem taksy jest Edwin Fernando.  ⁇ Fernando ⁇ - singel ze zespołu ABBA.</p>", "Florin-David": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Feliks Tadeusz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Feliks</b>.</p><b>Feliks</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>felix</em> – łaskawy, szczęśliwy) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Żeńskie odpowiedniki: <a href=\"https://pl.wikipedia.org/wiki/Feliksa\" target=\"_blank\" rel=\"noopener noreferrer\">Feliksa</a>, <a href=\"https://pl.wikipedia.org/wiki/Felicja\" target=\"_blank\" rel=\"noopener noreferrer\">Felicja</a>.", "Fuyu": "Pod koniec panowania <a href=\"https://pl.wikipedia.org/wiki/Dynastia_Han#Wschodnia_Dynastia_Han\" target=\"_blank\" rel=\"noopener noreferrer\">Wschodnich Hanów</a>, chiński gubernator wojskowy Gongsun Du w <a href=\"https://pl.wikipedia.org/wiki/Liaotung\" target=\"_blank\" rel=\"noopener noreferrer\">Liaodong</a> wspomógł Buyeo odeprzeć ataki <a href=\"https://pl.wikipedia.org/wiki/Xianbei\" target=\"_blank\" rel=\"noopener noreferrer\">Xianbei</a> na północy i <a href=\"https://pl.wikipedia.org/wiki/Goguryeo\" target=\"_blank\" rel=\"noopener noreferrer\">Goguryeo</a> na wschodzie. Po zniszczeniu rodziny Gongsun&#65279;<a href=\"https://www.wikidata.org/wiki/Q3268466#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a>, <a href=\"https://pl.wikipedia.org/wiki/Wei_(Okres_Trzech_Kr%C3%B3lestw)\" target=\"_blank\" rel=\"noopener noreferrer\">królestwo Wei</a> wysłało Wuqiu Jian&#65279;<a href=\"https://www.wikidata.org/wiki/Q736639#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a>, by zaatakował Goguryeo. Oddział trzeciego korpusu ekspedycyjnego dostarczył do Chin szczegółowe informacje na temat Buyeo.", "Fréderic": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Frederik</b>.</p><p>Frederik (d. 11 października 1753 - 7 grudnia 1805) - królewski książę Danii i Norwegii, syn króla Fredericka V i jego drugiej żony Juliany Marie Braunschweig-Wolfenbütetelski.</p>", "Fredy Leonel": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fredy</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fredi</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fred</b>.</p><p>August Frederick ⁇ Fred\" Kammer Jr.; 3 czerwca 1912, Brooklyn - 21 lutego 1996, Hob-Sound) - amerykański hokejista i golfa, brązowy zwycięzca zimowych igrzysk olimpijskich 1936.</p>", "Florin-George": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Fernando Alberto": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Fernando</b>.</p><p>Fernando: Fernando - hiszpańskie imię i nazwisko Fernando - skrócenie botaniczne, które oznacza, że autorem taksy jest Edwin Fernando.  ⁇ Fernando ⁇ - singel ze zespołu ABBA.</p>", "Felix Alberto": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Felix</b>.</p><p>Felix (lat. Felix - ⁇ płodny, owocny, szczęśliwy, dobrobytny, błogosławiony, bogaty) - imię męskie.</p>", "F": "<b>F</b> (wymowa: <i>ef</i>, <a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>f</b>) – szósta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a>, dziewiąta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_polski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu polskiego</a>. Oznacza zwykle w danym języku <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_wargowo-z%C4%99bowa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">spółgłoskę szczelinową wargowo-zębową bezdźwięczną</a>, np. [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_wargowo-z%C4%99bowa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">f</a>].", "Franz Wilhelm": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Franz</b>.</p><p>Franz (niemiecki Franz, od frank - ⁇ wolny, odważny ⁇) - niemieckie imię męskie.</p>", "Franco Ivan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Franco</b>.</p><p>Juan Manuel Antonio do Amaral Franco (port. João Manuel Antonio do Amaral Franco; 25 czerwca 1921 - 8 maja 2009) - portugalski botanik, profesor botaniki, ⁇ patryarch portugalskich botaniki ⁇ .</p>", "Franciszek Wiesław": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Franciszek</b>.</p><b>Franciszek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie wywodzące się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a> określenia <i>francesco</i> oznaczającego \"Francuza, Francuzika\", jakim kupiec Piotr Bernardone (ojciec <a href=\"https://pl.wikipedia.org/wiki/Franciszek_z_Asy%C5%BCu\" target=\"_blank\" rel=\"noopener noreferrer\">św. Franciszka z Asyżu</a>) nazwał swego syna Jana, gdy ten wrócił z Francji. W Asyżu zaczęto powszechnie nazywać chłopca tym określeniem i pod takim imieniem znany jest powszechnie.", "Francisco De Paula": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Francisco</b>.</p><p>Francisco (hisp. Francisco) - hiszpańskie imię i nazwisko męskie, w innych językach występują warianty - Francisco, Francesco, Francisc.</p>", "Florin-Alin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Florin-Moise": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Francois Marie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>François</b>.</p><p>François (francuski) - francuskie imię i nazwisko mężczyzn (włoski - Francuasa).</p>", "Florin-Marian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Florin-Ionuţ": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Faith": "<p>Faith to nazwa kilku utworów. Faith to album The Cure.</p>", "Frank Javier": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Frank</b>.</p><p>Frank - debiutancki album studiowy brytyjskiej piosenkarki Amy Winehouse, wydany 20 października 2003 roku przez Island Records. Album zajął trzynaste miejsce w brytyjskich listach.</p>", "Florin-Nicuşor": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Fernando David": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Fernando</b>.</p><p>Fernando: Fernando - hiszpańskie imię i nazwisko Fernando - skrócenie botaniczne, które oznacza, że autorem taksy jest Edwin Fernando.  ⁇ Fernando ⁇ - singel ze zespołu ABBA.</p>", "Francisco Iii": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Francisco</b>.</p><p>Francisco (hisp. Francisco) - hiszpańskie imię i nazwisko męskie, w innych językach występują warianty - Francisco, Francesco, Francisc.</p>", "François-Joseph": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>François</b>.</p><p>François (francuski) - francuskie imię i nazwisko mężczyzn (włoski - Francuasa).</p>", "Francisco Alexander": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Francisco</b>.</p><p>Francisco (hisp. Francisco) - hiszpańskie imię i nazwisko męskie, w innych językach występują warianty - Francisco, Francesco, Francisc.</p>", "Florin-Nicolae": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Fakhry": "<p>Fakhri lub Fakhry lub Fachri to arabskie imię i nazwisko. Fahri to turecki odpowiednik.</p>", "Florin-Antoniu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Faadil": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fadil</b>.</p><p>Fazl (arabski: فضل) to arabskie słowo oznaczające łaskę lub cnótę. Może być również przetłumaczana jako Fadl lub z dodaniem dodatkowej vokalu.</p>", "Fanil": "<p>Fanil (rosyjski: Фанил) to męskie imię. Wśród znanych osób z nazwiskiem są: Fanil Sungatulin (ur. 2001), rosyjski piłkarz Fanil Sarvarov (1969-2025), rosyjskie porucznik generalny</p>", "Freyr": "<b>Frejr</b> (także Frej, Frey, Freyr, Yngwe) – bóstwo falliczne z rodu <a href=\"https://pl.wikipedia.org/wiki/Wanowie\" target=\"_blank\" rel=\"noopener noreferrer\">Wanów</a>, bóg urodzaju, roślinności, pokoju, płodności, bogactwa i radości, syn <a href=\"https://pl.wikipedia.org/wiki/Nj%C3%B6r%C3%B0r\" target=\"_blank\" rel=\"noopener noreferrer\">Njörðra</a> i <a href=\"https://pl.wikipedia.org/wiki/Skadi\" target=\"_blank\" rel=\"noopener noreferrer\">Skadi</a> (albo nieznanej z imienia siostry Njörda), brat <a href=\"https://pl.wikipedia.org/wiki/Freja\" target=\"_blank\" rel=\"noopener noreferrer\">Frei</a>. Władca świetlistych Alfów, jego małżonką jest uosabiająca ziemię <a href=\"https://pl.wikipedia.org/wiki/Gerda\" target=\"_blank\" rel=\"noopener noreferrer\">Gerda</a>.", "Faramir": "Pojawia się w jej kolejnych częściach <i><a href=\"https://pl.wikipedia.org/wiki/W%C5%82adca_Pier%C5%9Bcieni\" target=\"_blank\" rel=\"noopener noreferrer\">Władcy Pierścieni</a>:</i> <i><a href=\"https://pl.wikipedia.org/wiki/Dwie_wie%C5%BCe\" target=\"_blank\" rel=\"noopener noreferrer\">Dwóch wieżach</a></i> i <i><a href=\"https://pl.wikipedia.org/wiki/Powr%C3%B3t_kr%C3%B3la\" target=\"_blank\" rel=\"noopener noreferrer\">Powrocie króla</a></i>. Więcej informacji na jego temat zawierają też <i>Dodatki</i> do trzeciego tomu oraz tom dwunasty <i><a href=\"https://pl.wikipedia.org/wiki/Historia_%C5%9Ar%C3%B3dziemia\" target=\"_blank\" rel=\"noopener noreferrer\">Historii Śródziemia</a></i>.", "François Pierre": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>François</b>.</p><p>François (francuski) - francuskie imię i nazwisko mężczyzn (włoski - Francuasa).</p>", "Franklin Rafael": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Franklin</b>.</p><p>James Franklin (około 1783 - 31 sierpnia 1834) - brytyjski żołnierz i naturalista.</p>", "Frédéri̇c": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Frederik</b>.</p><p>Frederik (d. 11 października 1753 - 7 grudnia 1805) - królewski książę Danii i Norwegii, syn króla Fredericka V i jego drugiej żony Juliany Marie Braunschweig-Wolfenbütetelski.</p>", "Franciszek Michał": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Franciszek</b>.</p><b>Franciszek</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie wywodzące się z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskiego</a> określenia <i>francesco</i> oznaczającego \"Francuza, Francuzika\", jakim kupiec Piotr Bernardone (ojciec <a href=\"https://pl.wikipedia.org/wiki/Franciszek_z_Asy%C5%BCu\" target=\"_blank\" rel=\"noopener noreferrer\">św. Franciszka z Asyżu</a>) nazwał swego syna Jana, gdy ten wrócił z Francji. W Asyżu zaczęto powszechnie nazywać chłopca tym określeniem i pod takim imieniem znany jest powszechnie.", "Fabian Alexander": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Fabian</b>.</p><b>Fabian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „należący do Fabiusza” (mężczyzny z rodu Fabiuszów). Nazwa rodowa Fabiuszy wywodzi się zaś od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>faba</em> (<a href=\"https://pl.wikipedia.org/wiki/B%C3%B3b\" target=\"_blank\" rel=\"noopener noreferrer\">bób</a>) i pierwotnie oznaczała osobę zajmującą się uprawą bobu. Chrześcijańskim patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Fabian_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Fabian, papież</a>.", "Fathalla": "<p>Fathallah, Fathalla lub tureckie wariant Fethullah jest transliteracją arabskiej nazwy, فتح الله (Fatḥ Allāh), zbudowane z arabskich słów fath i Allah. Jest to jedno z wielu arabskich nazw teoforycznych, które oznaczają \"otwarcie (otwarcie) Allaha\" lub \"podbojowanie Boga\".</p>", "Florin-Cătălin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Florin-Constantin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Franz Josef": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Franz</b>.</p><p>Franz (niemiecki Franz, od frank - ⁇ wolny, odważny ⁇) - niemieckie imię męskie.</p>", "Florin-Eleodor": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Florin-Ionuț": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Fayek": "<p>Fayek to arabskie słowo pochodzenia, które jest używane jako nazwisko i męskie nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Faidon": "<p>Phaedon (grecki: Φαίδων) to greckie imię. Można ją również przetłumaczyć jako Phaedo, Fedon lub Faidon.</p>", "Franz-Ferdinand": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Franz</b>.</p><p>Franz (niemiecki Franz, od frank - ⁇ wolny, odważny ⁇) - niemieckie imię męskie.</p>", "Fabian Leonardo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Fabian</b>.</p><b>Fabian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „należący do Fabiusza” (mężczyzny z rodu Fabiuszów). Nazwa rodowa Fabiuszy wywodzi się zaś od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>faba</em> (<a href=\"https://pl.wikipedia.org/wiki/B%C3%B3b\" target=\"_blank\" rel=\"noopener noreferrer\">bób</a>) i pierwotnie oznaczała osobę zajmującą się uprawą bobu. Chrześcijańskim patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Fabian_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Fabian, papież</a>.", "François Alain": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>François</b>.</p><p>François (francuski) - francuskie imię i nazwisko mężczyzn (włoski - Francuasa).</p>", "Fabian Fernando": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Fabian</b>.</p><b>Fabian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „należący do Fabiusza” (mężczyzny z rodu Fabiuszów). Nazwa rodowa Fabiuszy wywodzi się zaś od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>faba</em> (<a href=\"https://pl.wikipedia.org/wiki/B%C3%B3b\" target=\"_blank\" rel=\"noopener noreferrer\">bób</a>) i pierwotnie oznaczała osobę zajmującą się uprawą bobu. Chrześcijańskim patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Fabian_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Fabian, papież</a>.", "Febron": "<b>Febron</b>, <b>Febroniusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>Febronius</i>), pochodzące od imienia bóstwa <a href=\"https://pl.wikipedia.org/wiki/Etruskowie\" target=\"_blank\" rel=\"noopener noreferrer\">etruskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Februus\" target=\"_blank\" rel=\"noopener noreferrer\">Februus</a>, oznaczające \"poświęcony bogu Februusowi\". Znane w Polsce od średniowiecza, w formie <i><b>F(i)ebron</b></i>//<i><b>F(i)ebroń</b></i> (zdrobniale F(i)ebronek), także F(i)ebrun//F(i)ebruń oraz Świebron//Świebruń. Występuje również w staroukraińskim jako <i>Фебрунь</i>. Brak męskiego patrona w Kościele katolickim. Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Febronia_z_Nisibis\" target=\"_blank\" rel=\"noopener noreferrer\">św. Febronia z Nisbis</a>, zmarła w <a href=\"https://pl.wikipedia.org/wiki/304\" target=\"_blank\" rel=\"noopener noreferrer\">304</a> roku śmiercią męczeńską.", "François-Marie": "<p>François-Marie to francuskie męskie imię i może odnosić się do: Auguste François-Maré de Colbert-Chabanais (1777-1809), francuskiego generała François-Marée, 1st duc de Broglie (1671-1745), francuskiego dyplomata François-María, hrabiega de Broglia (1611-1656), francuskiego żołnierza François-Maria, markisa de Barthélemy (1747-1830), francuskiego polityka i dyplomatyka François-Marí Algoud (1920-2012), francuskiego pisarza François-marie Arouet (znane również jako: Voltaire;...</p>", "Fiach": "<p>Fiach to irlandzkie imię męskie. Może odnosić się do: Św. Fiacc, piątego wieku biskup Sletty w Irlandii Fiach McHugh O'Byrne (1534-1597) irlandzki szef Fiach Mac Conghail (ur. 1964) irlandzki dyrektor teatralny i senator Fiach Moriarty, irlandzki piosenkarz-powieściarz</p>", "Ferdinand Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Ferdinand</b>.</p><p>⁇ Ferdinand ⁇ (niem. Ferdinand) - niemiecka ciężka samodzielna-artyleryjna instalacja okresu II wojny światowej klasy myśliwców czołgów.</p>", "Florin-Vasile": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Fayez Labib": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Fayez</b>.</p><p>Fayez (arabsko: فَائِز) to arabskie imię dla mężczyzn, wariant Faiz. Mieszkańcy nazwanych Fayez to: Fayez Bandar (ur. 1983), Kuwaicki piłkarz Fayez Ghosn (1950-2021), libański polityk Fayez Sarofim (1929-2022), koptycki egipski amerykański menedżer funduszy Fayez al-Tarawneh (1949-2021), były premier Jordanii</p>", "Fengyuan": "Populacja dzielnicy Fengyuan w 2016 roku liczyła 166&#160;778 mieszkańców – 84&#160;268 kobiet i 82&#160;510 mężczyzn. Liczba gospodarstw domowych wynosiła 53&#160;191, co oznacza, że w jednym gospodarstwie zamieszkiwało średnio 3,14 osób.", "Fulko": "<b>Fulko</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_p%C3%B3%C5%82nocnogerma%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">skandynawskiego</a> słowa <i>folk</i> oznaczającego „lud, ludzie”. Istnieje kilku świętych o tym imieniu.", "Florus": "Autor zachowanego \"Zarysu dziejów rzymskich\" (<i>Epitomae de Tito Livio bellorum omnium annorum septingentorum libri duo</i>) w 2 księgach. Dla datowania <i>Epitomy</i> pomocna jest wzmianka we wstępie o cesarzu <a href=\"https://pl.wikipedia.org/wiki/Trajan\" target=\"_blank\" rel=\"noopener noreferrer\">Trajanie</a> oraz informacja, że od Cezara <a href=\"https://pl.wikipedia.org/wiki/Oktawian_August\" target=\"_blank\" rel=\"noopener noreferrer\">Augusta</a> do czasów Florusa minęło niewiele mniej niż 200 lat. Głównym źródłem Florusa był <a href=\"https://pl.wikipedia.org/wiki/Tytus_Liwiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Tytus Liwiusz</a>. <a href=\"https://pl.wikipedia.org/wiki/Salustiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Salustiusz</a> dostarczył mu natomiast materiału do opisu <a href=\"https://pl.wikipedia.org/wiki/Wojna_jugurty%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">wojen z Jugurtą</a> i <a href=\"https://pl.wikipedia.org/wiki/Katylina\" target=\"_blank\" rel=\"noopener noreferrer\">Katyliną</a>, a <a href=\"https://pl.wikipedia.org/wiki/Gajusz_Juliusz_Cezar\" target=\"_blank\" rel=\"noopener noreferrer\">Cezar</a> do opisu <a href=\"https://pl.wikipedia.org/wiki/Wojny_galijskie\" target=\"_blank\" rel=\"noopener noreferrer\">podboju Galii</a> i wojny z <a href=\"https://pl.wikipedia.org/wiki/Pompejusz\" target=\"_blank\" rel=\"noopener noreferrer\">Pompejuszem</a>. Jego praca jest krótką syntezą dziejów Rzymu, od założenia miasta aż do <a href=\"https://pl.wikipedia.org/wiki/9\" target=\"_blank\" rel=\"noopener noreferrer\">9 n.e.</a>, napisaną w duchu <a href=\"https://pl.wikipedia.org/wiki/Historiografia\" target=\"_blank\" rel=\"noopener noreferrer\">historiografii</a> <a href=\"https://pl.wikipedia.org/wiki/Stoicyzm\" target=\"_blank\" rel=\"noopener noreferrer\">stoickiej</a>. Florus przedstawił historię narodu rzymskiego według podziału na podstawie analogii z okresami życia człowieka - okres dzieciństwa, młodości, wieku dojrzałego i starości. Dziełko to pod względem formy stanowi przykład kwiecistego stylu retorycznego, panującego w ówczesnej literaturze rzymskiej. Mimo niewielkiej wartości historycznej książka przez długi czas była używana jako podręcznik szkolny, od starożytności aż do XVII wieku. Do naszych czasów zachowała się ponad setka rękopisów.", "Fabian Humberto": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Fabian</b>.</p><b>Fabian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „należący do Fabiusza” (mężczyzny z rodu Fabiuszów). Nazwa rodowa Fabiuszy wywodzi się zaś od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>faba</em> (<a href=\"https://pl.wikipedia.org/wiki/B%C3%B3b\" target=\"_blank\" rel=\"noopener noreferrer\">bób</a>) i pierwotnie oznaczała osobę zajmującą się uprawą bobu. Chrześcijańskim patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Fabian_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Fabian, papież</a>.", "Flavius-Alexandru": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Flavius</b>.</p><p>Flavius (lat. Flavius; zmarł 30 sierpnia 536) - biskup Reima (535 - 536).</p>", "Florin-Sasha": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florin</b>.</p><p>Karl Rudolf Florin (szwedzki. Carl Rudolf Florin lub Szwedzki.</p>", "Franklin Jr.": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Franklin</b>.</p><p>James Franklin (około 1783 - 31 sierpnia 1834) - brytyjski żołnierz i naturalista.</p>", "Franciszka": "<b>Franciszka</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Franciszek\" target=\"_blank\" rel=\"noopener noreferrer\">Franciszek</a>, pochodzi z języka włoskiego.", "Faustyna": "<b>Faustyna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>; żeńska forma imienia <a href=\"https://pl.wikipedia.org/wiki/Faustyn\" target=\"_blank\" rel=\"noopener noreferrer\">Faustyn</a>. Najbardziej znaną imienniczką i patronką tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Faustyna_Kowalska\" target=\"_blank\" rel=\"noopener noreferrer\">Faustyna Kowalska</a>. Łacińska grupa, od której imię to pochodzi (<i>faustus</i> — \"błogi, pomyślny\", ale także <i>faveo, favi, fautum</i> — \"sprzyjać, być przychylnym\") nie ma pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_indoeuropejskie\" target=\"_blank\" rel=\"noopener noreferrer\">indoeuropejskiego</a> oraz pewnych odpowiedników w żadnym języku indoeuropejskim.", "Felicja": "<b>Felicja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Feliks\" target=\"_blank\" rel=\"noopener noreferrer\">Feliks</a>, o tym samym znaczeniu.", "Feliksa": "<b>Feliksa</b> (łac. <i>felix</i> - łaskawy, szczęśliwy) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Feliks\" target=\"_blank\" rel=\"noopener noreferrer\">Feliks</a>.", "Florentyna": "<b>Florentyna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Florentyn\" target=\"_blank\" rel=\"noopener noreferrer\">Florentyn</a>. Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Florentyna_z_Kartageny\" target=\"_blank\" rel=\"noopener noreferrer\">św. Florentyna z Kartageny</a>, siostra św. <a href=\"https://pl.wikipedia.org/wiki/Izydor_z_Sewilli\" target=\"_blank\" rel=\"noopener noreferrer\">Izydora</a> i św. <a href=\"https://pl.wikipedia.org/wiki/Leander_z_Sewilli\" target=\"_blank\" rel=\"noopener noreferrer\">Leandra z Sewilli</a>.", "Filomena": "<b>Filomena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;φίλος („drogi; miły; przyjaciel”) i μενος („męstwo, siła życiowa”). W Polsce stosowane od XIV wieku.", "Fatima": "<b>Fatima</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>, tłumaczone jako „powstrzymująca się, powściągliwa” lub „odejmować dziecko od piersi”, co w przenośni oznaczałoby kogoś, kto wyszedł z wieku niemowlęcego. Imię to jest w świecie muzułmańskim nadawane na cześć <a href=\"https://pl.wikipedia.org/wiki/Fatima_(c%C3%B3rka_Mahometa)\" target=\"_blank\" rel=\"noopener noreferrer\">ukochanej córki proroka Mahometa</a> i w związku z tym popularne w kulturze <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islamskiej</a>. <a href=\"https://pl.wikipedia.org/wiki/F%C3%A1tima\" target=\"_blank\" rel=\"noopener noreferrer\">Fátima</a> to także nazwa miasta w <a href=\"https://pl.wikipedia.org/wiki/Portugalia\" target=\"_blank\" rel=\"noopener noreferrer\">Portugalii</a>, będącego ośrodkiem <a href=\"https://pl.wikipedia.org/wiki/Kult_maryjny\" target=\"_blank\" rel=\"noopener noreferrer\">kultu maryjnego</a> i celem wielu <a href=\"https://pl.wikipedia.org/wiki/Pielgrzymka\" target=\"_blank\" rel=\"noopener noreferrer\">pielgrzymek</a> <a href=\"https://pl.wikipedia.org/wiki/Katolicyzm\" target=\"_blank\" rel=\"noopener noreferrer\">katolickich</a>.", "Fryderyka": "<b>Fryderyka</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Fryderyk_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Fryderyk</a>.", "Flora": "<b>Flora</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pochodzące od imienia <a href=\"https://pl.wikipedia.org/wiki/Flora_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiej bogini</a> kwiatów i wiosny. W <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> po raz pierwszy poświadczone w 1375 roku. Patronką imienia jest m.in. <a href=\"https://pl.wikipedia.org/wiki/Flora_i_Maria\" target=\"_blank\" rel=\"noopener noreferrer\">św. Flora z Kordoby</a>.", "Fabiola": "<b>Fabiola</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia łacińskiego, pierwotnie zdrobniała forma imienia <a href=\"https://pl.wikipedia.org/wiki/Fabia\" target=\"_blank\" rel=\"noopener noreferrer\">Fabia</a>.", "Frida": "<p>Frida to imię kobiety, w tłumaczeniu z starego niemieckiego oznacza spokój.</p>", "Felicyta": "<b>Felicyta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, powstałe od wyrazu pospolitego <em>felicitas</em>, „urodzaj”, „szczęśliwość”, „błogosławieństwo”. Jedną z form zdrobniałych jest być może imię <a href=\"https://pl.wikipedia.org/wiki/Zyta\" target=\"_blank\" rel=\"noopener noreferrer\">Zyta</a>, obecnie funkcjonujące samodzielnie. Patronką tego imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/Felicyta_z_Kartaginy\" target=\"_blank\" rel=\"noopener noreferrer\">Felicyta z Kartaginy</a> (†203).", "Filipina": "<b>Filipina</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Filip\" target=\"_blank\" rel=\"noopener noreferrer\">Filip</a>. Patronką tego imienia jest św. Róża Filipina Duchesne (1769–1852).", "Florencia": "<p>Florencia może być: Florencia de Benito Juárez, miasto w Zacatecas, México Florencia, Caquetá, miasto we władzy Caqueta, Kolumbia Florencia, Cauca, miasto z władzy Cauca w władzy Florencia, Kolumbie, Kuba, miasto na terenie Ciego de Ávila w Kubie</p>", "Fiona": "Uważa się, że imię to jest <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">zlatynizowaną</a> formą <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_irlandzki\" target=\"_blank\" rel=\"noopener noreferrer\">irlandzkiego</a> słowa <i>fionn</i>, oznaczającego coś „białego”, „sprawiedliwego”, „uczciwego”. Imię <i>Fiona</i> jest też czasami używane w formie <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">zanglicyzowanej</a>, pochodnej od oryginalnej formy irlandzkiej imienia <i>Fíona</i>. Występuje także tendencja do wymiennego używania rzeczywistego <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_gaelicki_szkocki\" target=\"_blank\" rel=\"noopener noreferrer\">szkockiego</a> imienia <i>Fionnghal</i> i imienia <i>Fiona</i> (jest też możliwe, że imię <i>Fiona</i> było utworzone na bazie imienia <i>Fionnghal</i>).", "Fryda": "<b>Fryda</b> – skrócona forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Fryderyka\" target=\"_blank\" rel=\"noopener noreferrer\">Fryderyka</a>, <a href=\"https://pl.wikipedia.org/wiki/Elfryda\" target=\"_blank\" rel=\"noopener noreferrer\">Elfryda</a>, <a href=\"https://pl.wikipedia.org/wiki/Alfreda\" target=\"_blank\" rel=\"noopener noreferrer\">Alfreda</a>, <a href=\"https://pl.wikipedia.org/wiki/Fredegunda\" target=\"_blank\" rel=\"noopener noreferrer\">Fredegunda</a> lub Frydolina.", "Florianna": "<b>Florianna</b>, <b>Floriana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie; żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Florian\" target=\"_blank\" rel=\"noopener noreferrer\">Florian</a>, które z kolei pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>florus</i> – „kwitnący” i oznacza „należący do <i>Florusa</i>”. <b>Florianna</b> jest nadawana w Polsce od <a href=\"https://pl.wikipedia.org/wiki/XV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XV wieku</a>, a po raz pierwszy zapisana była w formie <i><b>Floryjana</b></i>. Zanotowano także zdrobnienie Floszka, oraz drugie, Tworka, które mogło pochodzić od Florianny z substytucją polską (jak Florian → Tworzyjan), lub też od imion rodzimych zaczynających się na <i>Tworzy-</i>.", "Freya": "<p>Freya (lat. Freya) - rodzaj pająków araneomorph z podrodzinnia Aelurillinae w rodzinie pająków-skakuonów (Salticidae).</p>", "Fabiana": "<b>Fabiana</b> (również <b>Pabiana</b>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwy <a href=\"https://pl.wikipedia.org/wiki/Cesarstwo_Rzymskie\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <a href=\"https://pl.wikipedia.org/wiki/Fabiusze\" target=\"_blank\" rel=\"noopener noreferrer\">Fabiuszów</a>. Żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Fabian\" target=\"_blank\" rel=\"noopener noreferrer\">Fabian</a>.", "Felicia": "<p>Felicia jest rodzajem roślin kwiatowych z rodziny Asteraceae.</p>", "Faina": "<b>Faina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie niejasnego pochodzenia, być może wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> imienia mitologicznego <i>Φαεννα (Phaenna)</i>, pochodzącego od <i>φαεινος (phaeinos)</i> – \"błyszczący, lśniący\". Imię to było przede wszystkim używane w Rosji. Jego patronką jest św. Faina, wspominana razem ze św. Aleksandrą, Klaudią, Eufrazją, Matroną, Julitą, Tekuzą i Teodotem.", "Flawia": "<b>Flawia</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Flawiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Flawiusz</a>. Istnieje kilka świętych patronek tego imienia.", "Florencja": "<b>Florencja</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego „kwitnący, pomyślny”.", "Fortunata": "<b>Fortunata</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Fortunat\" target=\"_blank\" rel=\"noopener noreferrer\">Fortunat</a>, oznacza „uszczęśliwona”.", "Filipa": "<b>Filipa</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Filip\" target=\"_blank\" rel=\"noopener noreferrer\">Filip</a>.", "Florentina": "<p>Florentina może odnosić się do: Święta Florentina, hiszpańska święta Andreea Florentina Grigore, rumuńska gimnastka artystyczna Florentina Bunea, rumuńskiej statystykarz Florentina Holzinger (ur. 1986), austriackiej choreografki, reżyserki i artysty performance Florentina Marincu, rumuński sportowca torbikowa Florentina Mosora, rumuńczyka i belgijska biofizyczka Florentina Nedelcu, rumunskiej kobiety z siatkówki Florentina Spânu, rumuinskiej piłkarki...</p>", "Freja": "Od staronordyckiego imienia bogini „Vanadís” pochodzi nazwa pierwiastka chemicznego <a href=\"https://pl.wikipedia.org/wiki/Wanad\" target=\"_blank\" rel=\"noopener noreferrer\">wanad</a>. Nazwę zaproponował w 1831, szwedzki chemik <a href=\"https://pl.wikipedia.org/wiki/Nils_Gabriel_Sefstr%C3%B6m\" target=\"_blank\" rel=\"noopener noreferrer\">Nils Gabriel Sefström</a>. Nazwę <a href=\"https://pl.wikipedia.org/wiki/(240)_Vanadis\" target=\"_blank\" rel=\"noopener noreferrer\">Vanadis (240)</a> nosi również <a href=\"https://pl.wikipedia.org/wiki/Planetoida\" target=\"_blank\" rel=\"noopener noreferrer\">planetoida</a> odkryta w 1884 roku przez <a href=\"https://pl.wikipedia.org/wiki/Alphonse_Louis_Nicolas_Borrelly\" target=\"_blank\" rel=\"noopener noreferrer\">Alphonse Borrelly’ego</a>.", "Fariza": "<p>Fariza jest miastem w prowincji Zamora, Kastilia i Leon, Hiszpania. Według przeprowadzonego w 2004 roku popytu (INE) mieście miało 689 mieszkańców.</p>", "Fiorella": "<p>Fiorella to włoskie nazwisko dla kobiet. Znanymi osobami z nazwiska są: Fiorella Aíta (ur. 1977), peruwiańska piłkarka siatkówki Fiorella Betti (1927-2001), włoską aktorka Fiorella Bonicelli (ur. 1951), uruguayska tenista Fiorella Chiappe (ur. 1996), argentyńską hamulcowka Fiorellę Cueva (ur. 1998), peruwka ciężarnoszkę Fiorella D'Croz Brusatin (ur. 1979), kolumbijska trójślubniczka Fiorella Faltoyano (ur. 1949), hiszpańska aktorka...</p>", "Florina": "<p>Florina (Grzecki: Φλώρινα, Flórina) jest samodzielnym terytorium w regionie Zachodniej Macedonii, Grecja. Autonomiczna dzielnica Florina ma powierzchnię 820 km2, populacja według badania z 18 marca 2001 roku wynosi 33588 osób.</p>", "Fatimah": "<p>Fāṭimah bint Muḥammad (/ˈfætəmə, ˈfɑːtiːˌmɑː/; arabski: فاطمة FāṭIMA; urodzona około 605 lub 615 - zmarła 28 sierpnia 632) była najmłodszą córką islamskiego proroka Muhammada i Khadijah, żony Ali'ego i matki Hasaana i Husseina, i jedną z członków Ahl al-Bayt. Była przedmiotem szacunku, miłości i szacunku wszystkich muzułmanów, ponieważ była bardzo blisko swojego ojca (prorok Muhammad) i wspierała go w...</p>", "Françoise": "<p>Francuaza: Francuza Madlen Orleanska (1648 - 1664) - urodzona księżniczka Francji, księżniczka Sawyjska. Fransoaza Orleanska (1902 - 1953) - francuska księżniczka z domu Orleanskiego.</p>", "Francoise": "<p>Françoise (francuski: [fʁɑ̃swaz]) to francuska nazwisko kobiety (odpowiadające angielskiej Francesce lub włoskiej Francesce) i może odnosić się do: Anne Françoise Elizabeth Lange (1772-1816), francuskiej aktorki Claudine Françoise Mignot (1624-1711), francuskiego przygódcy Françoise Adnet (1924-2014), francuskiego malarza figuratycznego Françoise Ardré (1931-2010), francuskiego fizycznego naukowca i naukowca morskich Françoise arnoul (1931-2021), francuską aktorkę Françoise Atlanço (ur. ...</p>", "Francine": "<p>⁇ Francine ⁇ , również w wielu wydaniach ⁇ Francene ⁇ (z angielskiego - ⁇ Fransin ⁇) - trzeci single amerykańskiej grupy blues-rock ZZ Top i pierwszy single grupy, który trafił do Billboard Hot 100.</p>", "Fleur": "<p>Flëur (czyta się: ⁇ Flёр ⁇) - ukraiński zespół muzyczny z Odesy, który istniał w latach 2000-2017.</p>", "Fedora": "<p>Fedora Linux (z angielskiego - ⁇ федора ⁇ , wcześniej - Fedora Core) - dystrybucja Linux, opracowana przez projekt Fedora przy komercyjnym wsparciu firm Red Hat i IBM i zawierająca możliwości, które w przyszłości są przeznaczone do wykorzystania w dystrybucji Red Hat Enterprise Linux.</p>", "Fabia": "<b>Fabia</b> – żeński odpowiednik łacińskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Fabiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Fabiusz</a>. Patronem tego imienia jest bł. Fabiusz (zm. w <a href=\"https://pl.wikipedia.org/wiki/303\" target=\"_blank\" rel=\"noopener noreferrer\">303</a> roku).", "Fathima": "<p>Fatima (arabsko: فَاطِمَة, Fāṭimah), również pisowana Fatimah, jest nazwą kobiet pochodzenia arabskiego stosowaną w całym świecie muzułmańskim. Kilku krewnych islamskiego proroka Mahometa nosiło to imię, w tym najbardziej znana jego córka Fatimah bint Muhammad.</p>", "Faustine": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Faustin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Faustyn</b>.</p><b>Faustyn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od rzymskiego nazwiska <i>Faustinus</i>, które pierwotnie oznaczało „pochodzący od <a href=\"https://pl.wikipedia.org/wiki/Faust_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Fausta</a>, należący do Fausta”. Imię to nosiło wielu świętych, a jednym ze znanych jest św. Faustyn, wspominany 15 lutego ze swoim bratem, św. <a href=\"https://pl.wikipedia.org/wiki/Jowita\" target=\"_blank\" rel=\"noopener noreferrer\">Jowitą</a>. Łacińska grupa, od której imię to pochodzi (<i>faustus</i> — „błogi, pomyślny”, ale także <i>faveo, favi, fautum</i> — „sprzyjać, być przychylnym”) nie ma pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_indoeuropejskie\" target=\"_blank\" rel=\"noopener noreferrer\">indoeuropejskiego</a> oraz pewnych odpowiedników w żadnym języku indoeuropejskim.", "Felicjana": "<b>Felicjana</b>, <b>Felicjanna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Felicjan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Felicjan</a>. <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">Imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/24_listopada\" target=\"_blank\" rel=\"noopener noreferrer\">24 listopada</a>, jako wspomnienie <a href=\"https://pl.wikipedia.org/wiki/Felicjana_de_Uribe_Orbe\" target=\"_blank\" rel=\"noopener noreferrer\">bł. Felicjany (Felicjanny) de Uribe Orbe</a>, karmelitańskiej siostry miłosierdzia.", "Freyja": "Od staronordyckiego imienia bogini „Vanadís” pochodzi nazwa pierwiastka chemicznego <a href=\"https://pl.wikipedia.org/wiki/Wanad\" target=\"_blank\" rel=\"noopener noreferrer\">wanad</a>. Nazwę zaproponował w 1831, szwedzki chemik <a href=\"https://pl.wikipedia.org/wiki/Nils_Gabriel_Sefstr%C3%B6m\" target=\"_blank\" rel=\"noopener noreferrer\">Nils Gabriel Sefström</a>. Nazwę <a href=\"https://pl.wikipedia.org/wiki/(240)_Vanadis\" target=\"_blank\" rel=\"noopener noreferrer\">Vanadis (240)</a> nosi również <a href=\"https://pl.wikipedia.org/wiki/Planetoida\" target=\"_blank\" rel=\"noopener noreferrer\">planetoida</a> odkryta w 1884 roku przez <a href=\"https://pl.wikipedia.org/wiki/Alphonse_Louis_Nicolas_Borrelly\" target=\"_blank\" rel=\"noopener noreferrer\">Alphonse Borrelly’ego</a>.", "Francy": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Franky</b>.</p><p>Frankie lub Franky mogą odnosić się do:</p>", "Febronia": "<b>Febronia</b> – pochodzące z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, przypuszczalnie wywiedzione od imienia bóstwa <a href=\"https://pl.wikipedia.org/wiki/Etruskowie\" target=\"_blank\" rel=\"noopener noreferrer\">etruskiego</a> <a href=\"https://pl.wikipedia.org/wiki/Februus\" target=\"_blank\" rel=\"noopener noreferrer\">Februusa</a>. Znane w Polsce od średniowiecza, również w formach Fiebronija, Febrocha i Feberka.", "Feodora": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Feodor</b>.</p><p>Fyodor, Fedor (rosyjski: Фёдор) lub Feodor jest rosyjską formą greckiego imienia Theodoros (grecki: Θεόδωρος) oznaczającego \"Boży dar\" lub \"od Boga\". Fedora (Федора) jest kobiecą formą.</p>", "Fatiha": "<b>Fatiha</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> <b>ﻓﺘﻴﺤﺔ</b>) – arabskie imię żeńskie. Pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Tytu%C5%82_(literaturoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">tytułu</a> pierwszej sury <a href=\"https://pl.wikipedia.org/wiki/Koran\" target=\"_blank\" rel=\"noopener noreferrer\">Koranu</a> <a href=\"https://pl.wikipedia.org/wiki/Al-Fatiha\" target=\"_blank\" rel=\"noopener noreferrer\">Al-Fatihy</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> الفاتحة).", "Fatema": "<p>Fatima (arabsko: فَاطِمَة, Fāṭimah), również pisowana Fatimah, jest nazwą kobiet pochodzenia arabskiego stosowaną w całym świecie muzułmańskim. Kilku krewnych islamskiego proroka Mahometa nosiło to imię, w tym najbardziej znana jego córka Fatimah bint Muhammad.</p>", "Florentine": "<p>Firenze (/fiˈrɛntse/ lub również powszechnie Florence w języku angielskim i francuskim) jest stolicą regionu Toskanii, Włoch Środkowego. Jest ośmimi najpopularniejszymi miastami Włoch i największym miastem regionu Toskanii, z populacją około 360,843 osób, a jednocześnie jest centralnym centrum Miasta Metropolitalnego Firenze oraz sercem rozszerzonego miastem Firenze-Prato-Pistoia o ponad 1,5 miliona mieszkańców.</p>", "Farhana": "<p>Farhana to imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą: Farhana Yamin (ur. 1965), brytyjski prawnik i działacz na rzecz zmian klimatu, zaangażowany w porozumienie paryskie Rumeen Farhana (ur. 1981), bangladeski prawnik, polityk Farhana Mili, bangladeszka aktorka filmowa i telewizyjna Farhana Afzal (ur. 1964), pakistańska polityk Farana Sheikh, brytyjsko-pakistańska pisarka, dramatyk i nauczyciel Farhana Sultana, bangladeski...</p>", "Fátima": "<p>Fátima (/ˈfatimɐ/) jest miastem w Portugalii, należącym do urzędu Ourém, w okręgu Santarém, w podziale \"Medio Tejo\", w regionie Środkowego Portugalii. Miasto ma 7 756 mieszkańców.</p>", "Franca": "<p>Franca to brazylijskie miasto, w którym funkcjonuje władza Franca. Miasto to w stanie São Paulo.</p>", "Fatyma": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fatima</b>.</p><b>Fatima</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>, tłumaczone jako „powstrzymująca się, powściągliwa” lub „odejmować dziecko od piersi”, co w przenośni oznaczałoby kogoś, kto wyszedł z wieku niemowlęcego. Imię to jest w świecie muzułmańskim nadawane na cześć <a href=\"https://pl.wikipedia.org/wiki/Fatima_(c%C3%B3rka_Mahometa)\" target=\"_blank\" rel=\"noopener noreferrer\">ukochanej córki proroka Mahometa</a> i w związku z tym popularne w kulturze <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islamskiej</a>. <a href=\"https://pl.wikipedia.org/wiki/F%C3%A1tima\" target=\"_blank\" rel=\"noopener noreferrer\">Fátima</a> to także nazwa miasta w <a href=\"https://pl.wikipedia.org/wiki/Portugalia\" target=\"_blank\" rel=\"noopener noreferrer\">Portugalii</a>, będącego ośrodkiem <a href=\"https://pl.wikipedia.org/wiki/Kult_maryjny\" target=\"_blank\" rel=\"noopener noreferrer\">kultu maryjnego</a> i celem wielu <a href=\"https://pl.wikipedia.org/wiki/Pielgrzymka\" target=\"_blank\" rel=\"noopener noreferrer\">pielgrzymek</a> <a href=\"https://pl.wikipedia.org/wiki/Katolicyzm\" target=\"_blank\" rel=\"noopener noreferrer\">katolickich</a>.", "Farzana": "<p>Farzaneh (perskie: فرزانه, Farzāneh, oznacza mądry, inteligentny lub wysoko wiedzą), również przetransliterowany jako Farzana, Farzona lub Farzane, jest perską nazwą dla dziewcząt powszechną w Iranie, Azji Południowej i Azji Środkowej. Mężczyzna jest Farzanem.</p>", "Florida": "<p>Florida - stan na południowo-wschodnim wschodzie USA; stolica - miasto Tallahassee. Położony jest na tym samym półwyspie pomiędzy Zatokiem Meksykańskim na zachód a Oceanem Atlantyckim na wschód, z południa płynie przez Prąg Florydy.</p>", "Fadia": "<p>Fádia (lat. Fadia; I wiek pne.</p>", "Fe": "<p>Żelazo (chymiczny symbol - Fe, od łacińskiego Ferrum) - element chemiczny 8 grupy (po przestarzałej klasyfikacji - uboczna podgrupa ósmej grupy, VIIIB) czwartego okresu okresowego systemu elementów chemicznych D.</p>", "Faten": "<p>Faten to nazwisko pochodzące z arabskiego języka. Do wybitnych osób z tym nazwiskiem należą:</p>", "Felicita": "<p>⁇ Felicità ⁇ (MFA: felitʃiˈta; z włoski - ⁇ Sczęście ⁇) - piosenka włoskiego duetu Al Bano i Rominy Power, wydana w 1982 roku.</p>", "Fabiane": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fabian</b>.</p><b>Fabian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „należący do Fabiusza” (mężczyzny z rodu Fabiuszów). Nazwa rodowa Fabiuszy wywodzi się zaś od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>faba</em> (<a href=\"https://pl.wikipedia.org/wiki/B%C3%B3b\" target=\"_blank\" rel=\"noopener noreferrer\">bób</a>) i pierwotnie oznaczała osobę zajmującą się uprawą bobu. Chrześcijańskim patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Fabian_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">św.&#160;Fabian, papież</a>.", "Fanta": "<p>Fanta (niem. Fanta) - bezalkoholowy, mocno gazowany napoi chłodzący z smakiem cytrusowym; wyprodukowany jest przez korporację Coca-Cola.</p>", "Fadila": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fadil</b>.</p><p>Fazl (arabski: فضل) to arabskie słowo oznaczające łaskę lub cnótę. Może być również przetłumaczana jako Fadl lub z dodaniem dodatkowej vokalu.</p>", "Flavie": "<p>Flavia to kobiece imię pochodzące z łacińskiego. Nazwa ta jest najczęściej stosowana w Włoszech, Rumunii, Brazylii (Portugalia i w krajach hiszpańskojęzycznych).</p>", "Franchesca": "<p>Franchesca to kobiece imię. Wśród znanych osób z tej nazwy są: Franchesca Caniguán, chilijska piłkarka Franchesca Floirendo, filipinańska aktorka, gospodarz i model Franchesca Ramsey, amerykański komiks, aktywista, aktorka telewizyjna i YouTube oraz Franchesca Salcedo, filipinska aktorka Jenilca Franchesca Giusti, portorykańska piosenkarka, autorka piosenek i aktorka</p>", "Fazila": "<p>Fazila to kobiece imię. Wśród znanych osób z tej nazwy są: Fazila Kaiser, pakistańska aktorka, producent, pisarz i szef kuchni Fazila Allana (ur. 1970), indyjska biznesmena Fazila Aliani (ur. 1945), pakistańska aktywistka i polityka Fazila Samadova (1929-2020), azerbajdżanską naukowcem</p>", "Farrah": "<p>Farah jest arabskim i perskim imieniem kobiece, które w pierwszej literce oznacza \"radość\" a w drugiej \"sława\". Nazwa arabska jest powszechna w całym świecie muzułmańskim, podczas gdy inne odmiany nazwy wzrosły w popularności w całej Anglosferze głównie dzięki amerykańskich gwiazdom Farrah Fawcett (1947-2009) i Farrah Abraham (urodzony w 1991); \"Farrah\" znalazł się wśród tysiąca najlepszych nazw dla noworodków w Stanach Zjednoczonych w latach 1976...</p>", "Fatuma": "<p>Fatuma to imię. Wśród znanych osób z tej nazwy są: Fatuma Abdulkadir Adan, kenijska prawnik i ambasador pokojowy Fatuma Abdullahi Insaniya, somalijska dyplomatka Fatuma Ali Saman, kenijska edukacja i działaczka na rzecz praw kobiet Fatuma binti Yusuf al-Alawi, królowa Unguja w pre-sultanatze Zanzibar Fatuma Gedi, kenijska politykka Fatuma Al Ibrahim Ali, kenijska Fatuma Masito, kenijska politika Fatuma Ndangiza, (urodzona w 1968 r.), Rwandanka...</p>", "Florinda": "<p>Florinda może odnosić się do: Nazwa Florinda jest łacińską z krajów Włochy, Hiszpanii i Portugalii. Pochodzi z słów Floris &amp; Flora (kwiecie) oznaczające kwiat (kwiecik kwitnący.) Florinda coccinea, czarnoogórza czerwona szata Florinda (serial telewizyjny) z Filipin Florinda, Florida, dawna społeczność Doña Florinda, postać z meksykańskiego komedii El Chavo del Ocho Jako nazwisko Florinda la Cava, legendarna Hiszpana Florinda Bolkan,...</p>", "Fidelia": "<b>Fidelisa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>fidelis</i>, ‘wierny, pewny’. Oznacza kobietę „pełną wiary”.", "Fara": "W <a href=\"https://pl.wikipedia.org/wiki/Etnolekt_%C5%9Bl%C4%85ski\" target=\"_blank\" rel=\"noopener noreferrer\">etnolekcie śląskim</a> fara oznacza budynek probostwa (podobnie jak w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">języku czeskim</a>), a farorzem mianuje się proboszcza danej parafii (czeski: farář).", "Felina": "<b>Felina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie; żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Felin_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Felin</a>, którego patronem jest św. Felin, towarzysz św. Gratyniana i razem z nim patron <a href=\"https://pl.wikipedia.org/wiki/Arona_(W%C5%82ochy)\" target=\"_blank\" rel=\"noopener noreferrer\">Arony</a>.", "Freia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Freya</b>.</p><p>Freya (lat. Freya) - rodzaj pająków araneomorph z podrodzinnia Aelurillinae w rodzinie pająków-skakuonów (Salticidae).</p>", "Fidelisa": "<b>Fidelisa</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>fidelis</i>, ‘wierny, pewny’. Oznacza kobietę „pełną wiary”.", "Ferida": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ferid</b>.</p><p>Farid (arabski: فَرِيد fariyd, farīd), również śpiewany Fareed lub Ferid i akcentujący się Férid, jest arabskim męskim imieniem osobistym lub nazwiskiem, które oznacza \"jedyną, jedyną w swoim rodzaju (\"Jeden\"), nieporównywalną\". W wielu społecznościach, w tym na Bliskim Wschodzie, na Bałkanach, w Afryce Północnej i Azji Południowo-Wschodniej, nazwa Farid jest powszechna przez wiele pokoleń.</p>", "Fortunate": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fortunat</b>.</p><b>Fortunat</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>.", "Felixa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Felix</b>.</p><p>Felix (lat. Felix - ⁇ płodny, owocny, szczęśliwy, dobrobytny, błogosławiony, bogaty) - imię męskie.</p>", "Filadelfia": "<b>Filadelfia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, od <i>φιλεω (fileo)</i> - \"kochać\" i <i>αδελφος (adelfos)</i> - \"brat\", co oznaczało \"braterska miłość\". Patronem tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Filadelf\" target=\"_blank\" rel=\"noopener noreferrer\">Filadelf</a>, wspominany razem ze swoimi braćmi, św. Alfiuszem i <a href=\"https://pl.wikipedia.org/wiki/Cyryn_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Cyrynem</a> (<a href=\"https://pl.wikipedia.org/wiki/III_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">III wiek</a>).", "Firmina": "<b>Firmina</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające \"należąca do <a href=\"https://pl.wikipedia.org/wiki/Firmus_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Firmusa</a>\" lub stanowiące żeńskie spieszczenie od imienia <a href=\"https://pl.wikipedia.org/wiki/Firmus_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Firmus</a>, które z kolei pochodzi od słowa <i>firmus</i> — \"mocny, pewny, stały, trwały\".", "Fumiko": "<b>Fumiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;ふみこ, フミコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Feri̇de": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ferid</b>.</p><p>Farid (arabski: فَرِيد fariyd, farīd), również śpiewany Fareed lub Ferid i akcentujący się Férid, jest arabskim męskim imieniem osobistym lub nazwiskiem, które oznacza \"jedyną, jedyną w swoim rodzaju (\"Jeden\"), nieporównywalną\". W wielu społecznościach, w tym na Bliskim Wschodzie, na Bałkanach, w Afryce Północnej i Azji Południowo-Wschodniej, nazwa Farid jest powszechna przez wiele pokoleń.</p>", "Frauke": "<p>Frauke to niemieckie imię. Do wybitnych osób z nazwiskiem należą: Frauke Brosius-Gersdorf (ur. 1971), niemiecki naukowiec prawny i profesor prawa publicznego Frauke Dirickx (ur. 1980), belgijski gracz siatkówki Frauke Eickhoff (ur. 1967), niemiecka judoka Frauke Eigen (ur. 1969), niemieckiej fotografki i artysty Frauke Finsterwalder (ur. 1975), niemieckoga reżyserka filmowa i scenarzystka Frauke Heard-Bey, niemiecki historyk,...</p>", "Fawzia": "<p>Fawzia lub Faouzia lub Fouzia (arabsko: فوزية) to arabskie imię kobiety oznaczające zwycięzcę. Znani ludzie z nazwą Fawzia lub alternatywnych pisowni obejmują:</p>", "Fereshteh": "<p>Fereshteh lub Ferishteh lub Freshteh lub Fresht (perskie: فرشته fereshteh/fereshtah) to kobiece imię pochodzenia perskiego oznaczające anioła, jedno z najbardziej popularnych nazw w świecie języka perskiego. Jest również przetłumaczana jako Freshteh lub Fereshta lub Farishta lub Freshta w innych językach, takich jak hindi, urdu, bengali i Dari wraz z perskim.</p>", "Fausta": "<b>Fausta</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Faust_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Faust</a>. Łacińska grupa, od której imię to pochodzi (<i>faustus</i> — \"błogi, pomyślny\", ale także <i>faveo, favi, fautum</i> — \"sprzyjać, być przychylnym\") nie ma pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_indoeuropejskie\" target=\"_blank\" rel=\"noopener noreferrer\">indoeuropejskiego</a> oraz pewnych odpowiedników w żadnym języku indoeuropejskim.", "Filona": "<b>Filona</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Filon\" target=\"_blank\" rel=\"noopener noreferrer\">Filon</a>, które pochodzi od <i>φιλεω (fileo)</i> – \"kochać\" i oznacza \"kochająca\". Patronem tego imienia jest św. Filon, wspominany razem ze św. Agatopodem.", "Fareeda": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fareed</b>.</p><p>Farid (arabski: فَرِيد fariyd, farīd), również śpiewany Fareed lub Ferid i akcentujący się Férid, jest arabskim męskim imieniem osobistym lub nazwiskiem, które oznacza \"jedyną, jedyną w swoim rodzaju (\"Jeden\"), nieporównywalną\". W wielu społecznościach, w tym na Bliskim Wschodzie, na Bałkanach, w Afryce Północnej i Azji Południowo-Wschodniej, nazwa Farid jest powszechna przez wiele pokoleń.</p>", "Flawiana": "<b>Flawiana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwy <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <a href=\"https://pl.wikipedia.org/wiki/Flawiusze\" target=\"_blank\" rel=\"noopener noreferrer\">Flawiuszów</a>. Oznacza \"należąca do Flawiusza, pochodząca od Flawiusza\". Patronką tego imienia jest św. Flawiana z <a href=\"https://pl.wikipedia.org/wiki/Auxerre\" target=\"_blank\" rel=\"noopener noreferrer\">Auxerre</a>.", "Farishta": "<p>Fereshteh lub Ferishteh lub Freshteh lub Fresht (perskie: فرشته fereshteh/fereshtah) to kobiece imię pochodzenia perskiego oznaczające anioła, jedno z najbardziej popularnych nazw w świecie języka perskiego. Jest również przetłumaczana jako Freshteh lub Fereshta lub Farishta lub Freshta w innych językach, takich jak hindi, urdu, bengali i Dari wraz z perskim.</p>", "Flor Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Flor</b>.</p><p>Gustav August Adam Flor (niem. Gustav August Flor; 1829 - 1883) - rosyjski entomolog, niemiecki bałtycki.</p>", "Faryal": "<p>Faryal (persk. فریال Faryâl; arabski: فَرْيَال Faryāl; azerbaińskie: Fəryal; tajczyckie: Фарёл, romanized: Faryol; tureckie: Feryal; urdu: فریال Fareāl; uzb. Jest to połączenie perskiego słowa فر (far) oznaczające \"wielkość\" i yal (yâl) oznaczające 'ganek'.</p>", "Fabianna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fabiana</b>.</p><b>Fabiana</b> (również <b>Pabiana</b>) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwy <a href=\"https://pl.wikipedia.org/wiki/Cesarstwo_Rzymskie\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <a href=\"https://pl.wikipedia.org/wiki/Fabiusze\" target=\"_blank\" rel=\"noopener noreferrer\">Fabiuszów</a>. Żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Fabian\" target=\"_blank\" rel=\"noopener noreferrer\">Fabian</a>.", "Fotina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fotyna</b>.</p><b>Fotyna</b> – żeńska forma imienia <a href=\"https://pl.wikipedia.org/wiki/Fotyn\" target=\"_blank\" rel=\"noopener noreferrer\">Fotyn</a>, pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodząca się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;φως, oznaczającego „światło, jasność”. Fotyna oznacza też „należąca do Focjusza, pochodząca od Focjusza”, przy czym imię Focjusz powstało bezpośrednio od słowa <i>phōs, phōtós</i>.", "Folake": "<p>Folake jest kobiece imieniem joruba używane w Nigerii, co oznacza \"przykręcanie się z bogactwem\" lub skrócony z dłuższych nazw jak Afọlákẹ́ lub Olúfọlákẹ̀. Znani ludzie z nazwiska to: Folake Akinyemi (ur. 1990), nigerijski-norweski sprinter Folake Coker (ur. 1974), nigerijska projektantka mody Folake Olayinka, nigerijski lekarz Folake Olowofoyeku (ur. 1983), nigerijskie aktorka i muzyka Folake Olunloyo, nigerijska polityk Folake Onayemi...</p>", "Fumi": "<b>Fumi</b> - japońskie imię żeńskie. Może być pisane znakami: 文; 史 lub kaną ふみ.", "Ferial": "<p>Ferial może być Alternatywne pisownianie perskiego imienia dziewcząt Faryal Odpowiadające się do dnia w kalendarzu starożytnego Rzymu, kiedy nie było wykonane żadnych prac; zobacz Glosarium starożytnej religii rzymskiej #feria Odpowiadający się do dni Feria - dni w kalendarzu Kościoła katolickiego, które nie są poświęcone żadnej świętej osobie lub wydarzeniu Roczne święto odbywane w Teatro Aguascalientes w Meksyku</p>", "Fathia": "<p>Fathia to kobiece imię arabskiego pochodzenia. Do wybitnych osób z tym nazwiskiem należą:</p>", "Farha": "<p>Farha lub Farhah (arabsko: فَرْحَة, farḥah) to arabskie unisex nazwisko i nazwisko, które oznacza \"wdzięczność, przyjemność, szczęście, szczęście\". Nazwa jest wariantem nazwiska Farhat i pochodzi również od nazwiska Farah.</p>", "Fernande": "<p>Fernande jest głównie francuskim językiem kobiece nazwisko. Jest to kobieca forma męskiego imienia Fernand.</p>", "Florie": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Flori</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Flor</b>.</p><p>Gustav August Adam Flor (niem. Gustav August Flor; 1829 - 1883) - rosyjski entomolog, niemiecki bałtycki.</p>", "Fatima-Ezzahra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Fatima</b>.</p><b>Fatima</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>, tłumaczone jako „powstrzymująca się, powściągliwa” lub „odejmować dziecko od piersi”, co w przenośni oznaczałoby kogoś, kto wyszedł z wieku niemowlęcego. Imię to jest w świecie muzułmańskim nadawane na cześć <a href=\"https://pl.wikipedia.org/wiki/Fatima_(c%C3%B3rka_Mahometa)\" target=\"_blank\" rel=\"noopener noreferrer\">ukochanej córki proroka Mahometa</a> i w związku z tym popularne w kulturze <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islamskiej</a>. <a href=\"https://pl.wikipedia.org/wiki/F%C3%A1tima\" target=\"_blank\" rel=\"noopener noreferrer\">Fátima</a> to także nazwa miasta w <a href=\"https://pl.wikipedia.org/wiki/Portugalia\" target=\"_blank\" rel=\"noopener noreferrer\">Portugalii</a>, będącego ośrodkiem <a href=\"https://pl.wikipedia.org/wiki/Kult_maryjny\" target=\"_blank\" rel=\"noopener noreferrer\">kultu maryjnego</a> i celem wielu <a href=\"https://pl.wikipedia.org/wiki/Pielgrzymka\" target=\"_blank\" rel=\"noopener noreferrer\">pielgrzymek</a> <a href=\"https://pl.wikipedia.org/wiki/Katolicyzm\" target=\"_blank\" rel=\"noopener noreferrer\">katolickich</a>.", "Fatima Ezzahra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Fatima</b>.</p><b>Fatima</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>, tłumaczone jako „powstrzymująca się, powściągliwa” lub „odejmować dziecko od piersi”, co w przenośni oznaczałoby kogoś, kto wyszedł z wieku niemowlęcego. Imię to jest w świecie muzułmańskim nadawane na cześć <a href=\"https://pl.wikipedia.org/wiki/Fatima_(c%C3%B3rka_Mahometa)\" target=\"_blank\" rel=\"noopener noreferrer\">ukochanej córki proroka Mahometa</a> i w związku z tym popularne w kulturze <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islamskiej</a>. <a href=\"https://pl.wikipedia.org/wiki/F%C3%A1tima\" target=\"_blank\" rel=\"noopener noreferrer\">Fátima</a> to także nazwa miasta w <a href=\"https://pl.wikipedia.org/wiki/Portugalia\" target=\"_blank\" rel=\"noopener noreferrer\">Portugalii</a>, będącego ośrodkiem <a href=\"https://pl.wikipedia.org/wiki/Kult_maryjny\" target=\"_blank\" rel=\"noopener noreferrer\">kultu maryjnego</a> i celem wielu <a href=\"https://pl.wikipedia.org/wiki/Pielgrzymka\" target=\"_blank\" rel=\"noopener noreferrer\">pielgrzymek</a> <a href=\"https://pl.wikipedia.org/wiki/Katolicyzm\" target=\"_blank\" rel=\"noopener noreferrer\">katolickich</a>.", "Feba": "<b>Feba</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia greckiego, od <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Φοιβη (Foibe), co oznaczało „jasna, czysta”. Imię to nosiło kilka postaci z <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii greckiej</a>. Od jednej z nich – tytanidy – pochodzi nazwa księżyca <a href=\"https://pl.wikipedia.org/wiki/Saturn\" target=\"_blank\" rel=\"noopener noreferrer\">Saturna</a>, <a href=\"https://pl.wikipedia.org/wiki/Febe_(ksi%C4%99%C5%BCyc)\" target=\"_blank\" rel=\"noopener noreferrer\">Febe</a>. Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Febe_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">św. Feba</a> z <a href=\"https://pl.wikipedia.org/wiki/Korynt\" target=\"_blank\" rel=\"noopener noreferrer\">Koryntu</a> wymieniona przez apostoła <a href=\"https://pl.wikipedia.org/wiki/Pawe%C5%82_z_Tarsu\" target=\"_blank\" rel=\"noopener noreferrer\">Pawła</a> w <a href=\"https://pl.wikipedia.org/wiki/List_do_Rzymian\" target=\"_blank\" rel=\"noopener noreferrer\">Liście do Rzymian</a> 16:1 jako <a href=\"https://pl.wikipedia.org/wiki/Diakon\" target=\"_blank\" rel=\"noopener noreferrer\">diakonisa</a> wczesnego Kościoła <a href=\"https://pl.wikipedia.org/wiki/Chrze%C5%9Bcija%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">chrześcijańskiego</a>.", "Felicjanna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Felicjana</b>.</p><b>Felicjana</b>, <b>Felicjanna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Felicjan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Felicjan</a>. <a href=\"https://pl.wikipedia.org/wiki/Imieniny\" target=\"_blank\" rel=\"noopener noreferrer\">Imieniny</a> obchodzi <a href=\"https://pl.wikipedia.org/wiki/24_listopada\" target=\"_blank\" rel=\"noopener noreferrer\">24 listopada</a>, jako wspomnienie <a href=\"https://pl.wikipedia.org/wiki/Felicjana_de_Uribe_Orbe\" target=\"_blank\" rel=\"noopener noreferrer\">bł. Felicjany (Felicjanny) de Uribe Orbe</a>, karmelitańskiej siostry miłosierdzia.", "Fekla": "<p>Fyokla lub Fekla (rosyjski: Фёкла) to starożytne rosyjskie imię pochodzące od greckiego Thekla (starożytny grecki: Θέκλα, Thékla, lit. 'Boża sławę').</p>", "Friderika": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fryderyka</b>.</p><b>Fryderyka</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Fryderyk_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Fryderyk</a>.", "Fathi Mohammed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Fathi</b>.</p><p>Fathi (arabsko: فَتْحِي fat·ḥiy/ fat·ḥī/ fat··ḥy) to arabskie imię i nazwisko w formie posiadanej, co oznacza \"wygrywający, triumfujący\". Może odnosić się do:</p>", "Franciszka Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Franciszka</b>.</p><b>Franciszka</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Franciszek\" target=\"_blank\" rel=\"noopener noreferrer\">Franciszek</a>, pochodzi z języka włoskiego.", "Fouzia": "<p>Fawzia lub Faouzia lub Fouzia (arabsko: فوزية) to arabskie imię kobiety oznaczające zwycięzcę. Znani ludzie z nazwą Fawzia lub alternatywnych pisowni obejmują:</p>", "Florina-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florina</b>.</p><p>Florina (Grzecki: Φλώρινα, Flórina) jest samodzielnym terytorium w regionie Zachodniej Macedonii, Grecja. Autonomiczna dzielnica Florina ma powierzchnię 820 km2, populacja według badania z 18 marca 2001 roku wynosi 33588 osób.</p>", "Fujiko": "<b>Fujiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;ふじこ, フジコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">japońskie imię żeńskie</a>.", "Fatima Zohra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Fatima</b>.</p><b>Fatima</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>, tłumaczone jako „powstrzymująca się, powściągliwa” lub „odejmować dziecko od piersi”, co w przenośni oznaczałoby kogoś, kto wyszedł z wieku niemowlęcego. Imię to jest w świecie muzułmańskim nadawane na cześć <a href=\"https://pl.wikipedia.org/wiki/Fatima_(c%C3%B3rka_Mahometa)\" target=\"_blank\" rel=\"noopener noreferrer\">ukochanej córki proroka Mahometa</a> i w związku z tym popularne w kulturze <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islamskiej</a>. <a href=\"https://pl.wikipedia.org/wiki/F%C3%A1tima\" target=\"_blank\" rel=\"noopener noreferrer\">Fátima</a> to także nazwa miasta w <a href=\"https://pl.wikipedia.org/wiki/Portugalia\" target=\"_blank\" rel=\"noopener noreferrer\">Portugalii</a>, będącego ośrodkiem <a href=\"https://pl.wikipedia.org/wiki/Kult_maryjny\" target=\"_blank\" rel=\"noopener noreferrer\">kultu maryjnego</a> i celem wielu <a href=\"https://pl.wikipedia.org/wiki/Pielgrzymka\" target=\"_blank\" rel=\"noopener noreferrer\">pielgrzymek</a> <a href=\"https://pl.wikipedia.org/wiki/Katolicyzm\" target=\"_blank\" rel=\"noopener noreferrer\">katolickich</a>.", "Flori": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Flor</b>.</p><p>Gustav August Adam Flor (niem. Gustav August Flor; 1829 - 1883) - rosyjski entomolog, niemiecki bałtycki.</p>", "Falka": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Falk</b>.</p><p>Johann (Юхан) Peter Falck (szwedzki Johan Peter Falck, 20 stycznia 1732 - 12 kwietnia (31 marca) 1774) - rosyjski i szwedzki podróżnik i naturalista (przede wszystkim botanik), badacz natury Rosji.</p>", "Florentina-Veronica": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florentina</b>.</p><p>Florentina może odnosić się do: Święta Florentina, hiszpańska święta Andreea Florentina Grigore, rumuńska gimnastka artystyczna Florentina Bunea, rumuńskiej statystykarz Florentina Holzinger (ur. 1986), austriackiej choreografki, reżyserki i artysty performance Florentina Marincu, rumuński sportowca torbikowa Florentina Mosora, rumuńczyka i belgijska biofizyczka Florentina Nedelcu, rumunskiej kobiety z siatkówki Florentina Spânu, rumuinskiej piłkarki...</p>", "Franklina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Franklin</b>.</p><p>James Franklin (około 1783 - 31 sierpnia 1834) - brytyjski żołnierz i naturalista.</p>", "Florina-Sonia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Florina</b>.</p><p>Florina (Grzecki: Φλώρινα, Flórina) jest samodzielnym terytorium w regionie Zachodniej Macedonii, Grecja. Autonomiczna dzielnica Florina ma powierzchnię 820 km2, populacja według badania z 18 marca 2001 roku wynosi 33588 osób.</p>", "Françoise Marie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Françoise</b>.</p><p>Francuaza: Francuza Madlen Orleanska (1648 - 1664) - urodzona księżniczka Francji, księżniczka Sawyjska. Fransoaza Orleanska (1902 - 1953) - francuska księżniczka z domu Orleanskiego.</p>", "Florije": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Florie</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Flori</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Flor</b>.</p><p>Gustav August Adam Flor (niem. Gustav August Flor; 1829 - 1883) - rosyjski entomolog, niemiecki bałtycki.</p>", "Fotyna": "<b>Fotyna</b> – żeńska forma imienia <a href=\"https://pl.wikipedia.org/wiki/Fotyn\" target=\"_blank\" rel=\"noopener noreferrer\">Fotyn</a>, pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecko</a>-<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodząca się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;φως, oznaczającego „światło, jasność”. Fotyna oznacza też „należąca do Focjusza, pochodząca od Focjusza”, przy czym imię Focjusz powstało bezpośrednio od słowa <i>phōs, phōtós</i>.", "Fanya": "<p>Agafangel (rosyjski: Агафа́нгел) to starożytne i rzadkie rosyjskie imię chrystiane męskie. Nazwa ta pochodzi od greckiego imienia Agathangelos, które z kolei pochodzi od słów agathos - oznaczających miłosierdzie, dobro - i angelos - oznaczającego nosiciela wieści, posłańca.</p>", "Fatima Zahra": "<b>Fatima bint Muhammad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;فاطمة بنت محمد&#8206;, ur. pomiędzy <a href=\"https://pl.wikipedia.org/wiki/600\" target=\"_blank\" rel=\"noopener noreferrer\">600</a> a <a href=\"https://pl.wikipedia.org/wiki/615\" target=\"_blank\" rel=\"noopener noreferrer\">615</a>, zm. <a href=\"https://pl.wikipedia.org/wiki/632\" target=\"_blank\" rel=\"noopener noreferrer\">632</a>) – córka proroka <a href=\"https://pl.wikipedia.org/wiki/Mahomet\" target=\"_blank\" rel=\"noopener noreferrer\">Mahometa</a> i jego żony <a href=\"https://pl.wikipedia.org/wiki/Chadid%C5%BCa\" target=\"_blank\" rel=\"noopener noreferrer\">Chadidży</a>. W 625 poślubiła kuzyna swego ojca, <a href=\"https://pl.wikipedia.org/wiki/Ali_ibn_Abi_Talib\" target=\"_blank\" rel=\"noopener noreferrer\">Alego</a>, ostatniego kalifa prawowiernego i pierwszego <a href=\"https://pl.wikipedia.org/wiki/Imam_(szyizm)\" target=\"_blank\" rel=\"noopener noreferrer\">imama</a>. Została matką <a href=\"https://pl.wikipedia.org/wiki/Husajn_ibn_Ali\" target=\"_blank\" rel=\"noopener noreferrer\">Husajna</a>, <a href=\"https://pl.wikipedia.org/wiki/Hasan_ibn_Ali\" target=\"_blank\" rel=\"noopener noreferrer\">Hasana</a>, Moszina i Zajnab. Członek <a href=\"https://pl.wikipedia.org/wiki/Ahl_al-Bajt\" target=\"_blank\" rel=\"noopener noreferrer\">rodziny</a> Mahometa. <a href=\"https://pl.wikipedia.org/wiki/Alidzi\" target=\"_blank\" rel=\"noopener noreferrer\">Potomkowie</a> Mahometa i wszyscy <a href=\"https://pl.wikipedia.org/wiki/Imam_(szyizm)\" target=\"_blank\" rel=\"noopener noreferrer\">imamowie</a> wywodzą się od niej i Alego.", "Feliksa Wiktoria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Feliksa</b>.</p><b>Feliksa</b> (łac. <i>felix</i> - łaskawy, szczęśliwy) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Jest żeńskim odpowiednikiem imienia <a href=\"https://pl.wikipedia.org/wiki/Feliks\" target=\"_blank\" rel=\"noopener noreferrer\">Feliks</a>.", "Fathiya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fathia</b>.</p><p>Fathia to kobiece imię arabskiego pochodzenia. Do wybitnych osób z tym nazwiskiem należą:</p>", "Freiia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Freia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Freya</b>.</p><p>Freya (lat. Freya) - rodzaj pająków araneomorph z podrodzinnia Aelurillinae w rodzinie pająków-skakuonów (Salticidae).</p>", "Floryna": "<b>Floryna</b> — <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia łacińskiego, pierwotnie <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">łaciński przydomek</a> pochodzący od imienia <i>Florus</i> („kwitnący”) i oznaczający „pochodząca od <i>Florusa</i>, córka <i>Florusa”</i>. Patronką imienia jest św. Floryna z Brioud (<a href=\"https://pl.wikipedia.org/wiki/Owernia\" target=\"_blank\" rel=\"noopener noreferrer\">Owernia</a>). Męski odpowiednik: <a href=\"https://pl.wikipedia.org/wiki/Floryn\" target=\"_blank\" rel=\"noopener noreferrer\">Floryn</a>.", "Funmi": "<p>Funmi to kobiece imię, które w języku joruba oznacza \"dla mnie\" lub \"oddaj mi\". Jest to diminutiwna wersja nazw takich jak: \"Olufunmilola/Oluwafunmiloła\" (Bóg dał mi bogactwo) lub \"Funmilola\" (daj mi bogactw) \"Olufunmilayo/Oluwa Funfunmilayo\" (Bog mi dał radość) lub \" Funmilayo\" (\"Daj mi radość\").</p>", "Fatima-Zahra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Fatima</b>.</p><b>Fatima</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>, tłumaczone jako „powstrzymująca się, powściągliwa” lub „odejmować dziecko od piersi”, co w przenośni oznaczałoby kogoś, kto wyszedł z wieku niemowlęcego. Imię to jest w świecie muzułmańskim nadawane na cześć <a href=\"https://pl.wikipedia.org/wiki/Fatima_(c%C3%B3rka_Mahometa)\" target=\"_blank\" rel=\"noopener noreferrer\">ukochanej córki proroka Mahometa</a> i w związku z tym popularne w kulturze <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islamskiej</a>. <a href=\"https://pl.wikipedia.org/wiki/F%C3%A1tima\" target=\"_blank\" rel=\"noopener noreferrer\">Fátima</a> to także nazwa miasta w <a href=\"https://pl.wikipedia.org/wiki/Portugalia\" target=\"_blank\" rel=\"noopener noreferrer\">Portugalii</a>, będącego ośrodkiem <a href=\"https://pl.wikipedia.org/wiki/Kult_maryjny\" target=\"_blank\" rel=\"noopener noreferrer\">kultu maryjnego</a> i celem wielu <a href=\"https://pl.wikipedia.org/wiki/Pielgrzymka\" target=\"_blank\" rel=\"noopener noreferrer\">pielgrzymek</a> <a href=\"https://pl.wikipedia.org/wiki/Katolicyzm\" target=\"_blank\" rel=\"noopener noreferrer\">katolickich</a>.", "Florenta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Florent</b>.</p><b>Florencjusz</b>, <b>Florenty</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, występujące w Polsce już w <a href=\"https://pl.wikipedia.org/wiki/XII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XII wieku</a> (<a href=\"https://pl.wikipedia.org/wiki/1175\" target=\"_blank\" rel=\"noopener noreferrer\">1175</a> r.). Powstało ono od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomka</a> <i>Florentius</i>, utworzonego poprzez dodanie <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostka</a> <i>-ius</i> od innego przydomka, <i>Florens</i> (łac. <i>florens</i>, <i>-ntis</i> — \"kwitnący\"). Istnieją liczni święci patroni tego imienia (nawet dwudziestu), m.in. św. <a href=\"https://pl.wikipedia.org/wiki/Florencjusz_z_Populonii\" target=\"_blank\" rel=\"noopener noreferrer\">Florencjusz z Populonii</a>, biskup (<a href=\"https://pl.wikipedia.org/wiki/IV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">IV wiek</a>).", "Folakemi": "<p>Fọ́lákẹ́mi to kobiece imię pochodzenia joruba, co oznacza \"używać bogactwa, aby mnie rozkoszować\".</p>", "Fathimah": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fatimah</b>.</p><p>Fāṭimah bint Muḥammad (/ˈfætəmə, ˈfɑːtiːˌmɑː/; arabski: فاطمة FāṭIMA; urodzona około 605 lub 615 - zmarła 28 sierpnia 632) była najmłodszą córką islamskiego proroka Muhammada i Khadijah, żony Ali'ego i matki Hasaana i Husseina, i jedną z członków Ahl al-Bayt. Była przedmiotem szacunku, miłości i szacunku wszystkich muzułmanów, ponieważ była bardzo blisko swojego ojca (prorok Muhammad) i wspierała go w...</p>", "Florenţa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Florent</b>.</p><b>Florencjusz</b>, <b>Florenty</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, występujące w Polsce już w <a href=\"https://pl.wikipedia.org/wiki/XII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XII wieku</a> (<a href=\"https://pl.wikipedia.org/wiki/1175\" target=\"_blank\" rel=\"noopener noreferrer\">1175</a> r.). Powstało ono od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomka</a> <i>Florentius</i>, utworzonego poprzez dodanie <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostka</a> <i>-ius</i> od innego przydomka, <i>Florens</i> (łac. <i>florens</i>, <i>-ntis</i> — \"kwitnący\"). Istnieją liczni święci patroni tego imienia (nawet dwudziestu), m.in. św. <a href=\"https://pl.wikipedia.org/wiki/Florencjusz_z_Populonii\" target=\"_blank\" rel=\"noopener noreferrer\">Florencjusz z Populonii</a>, biskup (<a href=\"https://pl.wikipedia.org/wiki/IV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">IV wiek</a>).", "Feryda": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ferida</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Ferid</b>.</p><p>Farid (arabski: فَرِيد fariyd, farīd), również śpiewany Fareed lub Ferid i akcentujący się Férid, jest arabskim męskim imieniem osobistym lub nazwiskiem, które oznacza \"jedyną, jedyną w swoim rodzaju (\"Jeden\"), nieporównywalną\". W wielu społecznościach, w tym na Bliskim Wschodzie, na Bałkanach, w Afryce Północnej i Azji Południowo-Wschodniej, nazwa Farid jest powszechna przez wiele pokoleń.</p>", "Farideh": "<p>Farida jest jednym z powszechnych nazw kobiet w całej kulturze Azji Zachodniej. W tureckim jest pisane jako Feride.</p>", "Fathema": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Fatema</b>.</p><p>Fatima (arabsko: فَاطِمَة, Fāṭimah), również pisowana Fatimah, jest nazwą kobiet pochodzenia arabskiego stosowaną w całym świecie muzułmańskim. Kilku krewnych islamskiego proroka Mahometa nosiło to imię, w tym najbardziej znana jego córka Fatimah bint Muhammad.</p>", "Flor De Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Flor</b>.</p><p>Gustav August Adam Flor (niem. Gustav August Flor; 1829 - 1883) - rosyjski entomolog, niemiecki bałtycki.</p>"};
